    __syncthreads();

    if (ij < sp_prim_pair_count_local)
    {
        i = sp_first_inds_local[ij];
        j = sp_second_inds_local[ij];

        a_i_f = s_prim_info_f[i + s_prim_count * 0];

        r_i_f[0] = s_prim_info_f[i + s_prim_count * 2];
        r_i_f[1] = s_prim_info_f[i + s_prim_count * 3];
        r_i_f[2] = s_prim_info_f[i + s_prim_count * 4];

        a_j_f = p_prim_info_f[j / 3 + p_prim_count * 0];

        r_j_f[0] = p_prim_info_f[j / 3 + p_prim_count * 2];
        r_j_f[1] = p_prim_info_f[j / 3 + p_prim_count * 3];
        r_j_f[2] = p_prim_info_f[j / 3 + p_prim_count * 4];

        S1_f = a_i_f + a_j_f;
        inv_S1_f = (float) (1.0 / (double)S1_f);

        S_ij_00_f = sp_pair_data_local_f[ij];

        b0 = j % 3;

        PB_0_f = (-a_i_f * inv_S1_f) * (r_j_f[b0] - r_i_f[b0]);

    }

    for (uint32_t m = prec_cut; m < screen_cut; m++)
    {
        const uint32_t kl = m * TILE_DIM + threadIdx.y;

        if ((ij >= sp_prim_pair_count_local) || (kl >= ss_prim_pair_count))
        {
            break;
        }

        const auto k = ss_first_inds[kl];
        const auto l = ss_second_inds[kl];

