                        +QC_0*(QC_1*(delta[a0][d0]*delta[b0][d1] + delta[a0][d1]*delta[b0][d0]) + QD_0*(delta[a0][c1]*delta[b0][d1] + delta[a0][d1]*delta[b0][c1]) + QD_1*(delta[a0][c1]*delta[b0][d0] + delta[a0][d0]*delta[b0][c1])) + QC_1*(QD_0*(delta[a0][c0]*delta[b0][d1] + delta[a0][d1]*delta[b0][c0]) + QD_1*(delta[a0][c0]*delta[b0][d0] + delta[a0][d0]*delta[b0][c0])) + QD_0*QD_1*(delta[a0][c0]*delta[b0][c1] + delta[a0][c1]*delta[b0][c0])

                        +PQ[a0]*PQ[b0]*(delta[c0][c1]*delta[d0][d1] + delta[c0][d0]*delta[c1][d1] + delta[c0][d1]*delta[c1][d0])
                    )

                    + 0.5 * S1 * S1 * inv_S2 * inv_S4 * inv_S4 * (
                        +PA_0*PB_0*delta[d0][d1]*(PQ[c0]*(PQ[c1] + QC_1) + PQ[c1]*QC_0)

                        +PA_0*PB_0*(PQ[d1]*(QC_0*delta[c1][d0] + QC_1*delta[c0][d0] + QD_0*delta[c0][c1]) + delta[c0][d1]*(PQ[c1]*(PQ[d0] + QD_0) + PQ[d0]*QC_1) + delta[c1][d1]*(PQ[c0]*(PQ[d0] + QD_0) + PQ[d0]*QC_0) + (PQ[d1] + QD_1)*(PQ[c0]*delta[c1][d0] + PQ[c1]*delta[c0][d0] + PQ[d0]*delta[c0][c1]))
