                        +delta[a0][b0]*(PQ[c0]*QD_0*(PQ[c1]*QD_1 + PQ[d1]*QC_1) + PQ[c1]*QC_0*(PQ[d0]*QD_1 + PQ[d1]*QD_0) + PQ[d0]*QC_1*(PQ[c0]*QD_1 + PQ[d1]*QC_0))
                    )

                    + 0.5 * S2 * inv_S4 * inv_S4 * (
                        +QC_0*QD_0*(PQ[a0]*(PQ[b0]*delta[c1][d1] + QC_1*delta[b0][d1] + QD_1*delta[b0][c1]) + PQ[b0]*(QC_1*delta[a0][d1] + QD_1*delta[a0][c1])) + QC_1*QD_1*(PQ[a0]*(QC_0*delta[b0][d0] + QD_0*delta[b0][c0]) + PQ[b0]*(QC_0*delta[a0][d0] + QD_0*delta[a0][c0]))

                        +PQ[a0]*PQ[b0]*(QC_1*(QC_0*delta[d0][d1] + QD_0*delta[c0][d1] + QD_1*delta[c0][d0]) + QD_1*(QC_0*delta[c1][d0] + QD_0*delta[c0][c1]))

                        +delta[a0][b0]*(QC_0*QD_1*(PQ[c1]*QD_0 + PQ[d0]*QC_1) + QC_1*QD_0*(PQ[c0]*QD_1 + PQ[d1]*QC_0))
                    )

                    + S1 * S1 * inv_S4 * inv_S4 * (
