                    )

                    + S1 * S2 * inv_S4 * inv_S4 * (
                        -(PA_0*PQ[b0] + PB_0*PQ[a0])*(QC_0*QD_1*(PQ[c1]*QD_0 + PQ[d0]*QC_1) + QC_1*QD_0*(PQ[c0]*QD_1 + PQ[d1]*QC_0))
                    )

                    + S2 * S2 * inv_S4 * inv_S4 * (
