        const double r_l[3] = {d_prim_info[l / 6 + d_prim_count * 2],
                               d_prim_info[l / 6 + d_prim_count * 3],
                               d_prim_info[l / 6 + d_prim_count * 4]};

        const auto S_kl_00 = sd_pair_data[kl];

        const auto d0 = d_cart_inds[l % 6][0];
        const auto d1 = d_cart_inds[l % 6][1];

        // J. Chem. Phys. 84, 3963-3974 (1986)

        const auto S2 = a_k + a_l;

        const auto inv_S2 = 1.0 / S2;
        const auto inv_S4 = 1.0 / (S1 + S2);

        const double PQ[3] = {(a_k * r_k[0] + a_l * r_l[0]) * inv_S2 - (a_i * r_i[0] + a_j * r_j[0]) * inv_S1,
                              (a_k * r_k[1] + a_l * r_l[1]) * inv_S2 - (a_i * r_i[1] + a_j * r_j[1]) * inv_S1,
                              (a_k * r_k[2] + a_l * r_l[2]) * inv_S2 - (a_i * r_i[2] + a_j * r_j[2]) * inv_S1};

        const auto r2_PQ = PQ[0] * PQ[0] + PQ[1] * PQ[1] + PQ[2] * PQ[2];

        const auto Lambda = sqrt(4.0 * S1 * S2 * MATH_CONST_INV_PI * inv_S4);

        double F4_t[5];

        gpu::computeBoysFunction(F4_t, S1 * S2 * inv_S4 * r2_PQ, 4, boys_func_table, boys_func_ft);

        const auto QD_0 = (-a_k * inv_S2) * (r_l[d0] - r_k[d0]);
        const auto QD_1 = (-a_k * inv_S2) * (r_l[d1] - r_k[d1]);

        const double eri_ijkl = Lambda * S_ij_00 * S_kl_00 * (

                + F4_t[0] * (

                    0.5 * inv_S1 * (
                        +QD_0*QD_1*delta[b0][b1]
                    )

                    + 0.5 * inv_S2 * (
                        +PB_0*PB_1*delta[d0][d1]
                    )

                    + (
                        +PB_0*PB_1*QD_0*QD_1
                    )

                    + 0.25 * inv_S1 * inv_S2 * (
                        +delta[b0][b1]*delta[d0][d1]
                    )

                )

                + F4_t[1] * (

                    (-0.25) * inv_S1 * inv_S4 * (
                        +delta[b0][b1]*delta[d0][d1]
                    )

                    + (-0.25) * inv_S2 * inv_S4 * (
                        +delta[b0][b1]*delta[d0][d1]
                    )

                    + (-0.5) * S1 * inv_S2 * inv_S4 * (
                        +PB_0*PB_1*delta[d0][d1]
                    )

                    + (-0.5) * S2 * inv_S1 * inv_S4 * (
                        +QD_0*QD_1*delta[b0][b1]
                    )

                    + 0.5 * inv_S4 * (
                        +delta[d0][d1]*(PB_0*PQ[b1] + PB_1*PQ[b0])

                        +PB_0*(QD_0*delta[b1][d1] + QD_1*delta[b1][d0]) + PB_1*(QD_0*delta[b0][d1] + QD_1*delta[b0][d0])

                        +delta[b0][b1]*(-PQ[d0]*QD_1 - PQ[d1]*QD_0)
                    )

                    + S1 * inv_S4 * (
                        +PB_0*PB_1*(-PQ[d0]*QD_1 - PQ[d1]*QD_0)
                    )

                    + S2 * inv_S4 * (
                        +QD_0*QD_1*(PB_0*PQ[b1] + PB_1*PQ[b0])
                    )

                )

                + F4_t[2] * (

                    0.5 * S1 * inv_S4 * inv_S4 * (
                        +delta[d0][d1]*(-PB_0*PQ[b1] - PB_1*PQ[b0])

                        -PB_0*(PQ[d0]*delta[b1][d1] + PQ[d1]*delta[b1][d0]) - PB_1*(PQ[d0]*delta[b0][d1] + PQ[d1]*delta[b0][d0])

                        +PQ[d0]*PQ[d1]*delta[b0][b1]
                    )

                    + 0.5 * S2 * inv_S4 * inv_S4 * (
                        +PQ[b0]*QD_0*delta[b1][d1]

                        +PQ[b1]*QD_0*delta[b0][d1] + QD_1*(PQ[b0]*delta[b1][d0] + PQ[b1]*delta[b0][d0])

                        +delta[b0][b1]*(PQ[d0]*QD_1 + PQ[d1]*QD_0)

                        +PQ[b0]*PQ[b1]*delta[d0][d1]
                    )

                    + S1 * S1 * inv_S4 * inv_S4 * (
                        +PB_0*PB_1*PQ[d0]*PQ[d1]
                    )

                    + S1 * S2 * inv_S4 * inv_S4 * (
                        -(PB_0*PQ[b1] + PB_1*PQ[b0])*(PQ[d0]*QD_1 + PQ[d1]*QD_0)
                    )

                    + S2 * S2 * inv_S4 * inv_S4 * (
                        +PQ[b0]*PQ[b1]*QD_0*QD_1
                    )

                    + 0.25 * inv_S4 * inv_S4 * (
                        +delta[b0][b1]*delta[d0][d1] + delta[b0][d0]*delta[b1][d1] + delta[b0][d1]*delta[b1][d0]
                    )

                )

                + F4_t[3] * (

                    (-0.5) * S1 * S2 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[b0]*PQ[b1]*delta[d0][d1]

                        +PQ[d0]*(PQ[b0]*delta[b1][d1] + PQ[b1]*delta[b0][d1] + PQ[d1]*delta[b0][b1]) + PQ[d1]*(PQ[b0]*delta[b1][d0] + PQ[b1]*delta[b0][d0])
                    )

                    + S1 * S1 * S2 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[d0]*PQ[d1]*(PB_0*PQ[b1] + PB_1*PQ[b0])
                    )

                    + S1 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[b0]*PQ[b1]*(-PQ[d0]*QD_1 - PQ[d1]*QD_0)
                    )

                )

                + F4_t[4] * (

                    S1 * S1 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[b0]*PQ[b1]*PQ[d0]*PQ[d1]
                    )

                )

                );

        // NOTE: doubling for off-diagonal elements of D due to k<=>l symmetry
        ERIs[threadIdx.y][threadIdx.x] += eri_ijkl * sd_mat_D[kl] * 2.0;

    }

    __syncthreads();

    if ((threadIdx.y == 0) && (ij < sd_prim_pair_count_local))
    {
        double J_ij = 0.0;

        for (uint32_t n = 0; n < TILE_DIM; n++)
        {
            J_ij += ERIs[n][threadIdx.x];
        }

        mat_J[ij] += J_ij;
    }
}

__global__ void __launch_bounds__(TILE_SIZE_J)
computeCoulombFockSDPP(double*         mat_J,
                       const double*   s_prim_info,
                       const uint32_t  s_prim_count,
                       const double*   p_prim_info,
                       const uint32_t  p_prim_count,
                       const double*   d_prim_info,
                       const uint32_t  d_prim_count,
                       const double*   pp_mat_D,
                       const double*   sd_mat_Q_local,
                       const double*   pp_mat_Q,
                       const uint32_t* sd_first_inds_local,
                       const uint32_t* sd_second_inds_local,
                       const double*   sd_pair_data_local,
                       const uint32_t  sd_prim_pair_count_local,
                       const uint32_t* pp_first_inds,
                       const uint32_t* pp_second_inds,
                       const double*   pp_pair_data,
                       const uint32_t  pp_prim_pair_count,
                       const double*   boys_func_table,
                       const double*   boys_func_ft,
                       const double    eri_threshold)
{
    // each thread row scans over [ij|??] and sum up to a primitive J matrix element
    // J. Chem. Theory Comput. 2009, 5, 4, 1004-1015

    __shared__ double   ERIs[TILE_DIM][TILE_DIM + 1];
    __shared__ uint32_t d_cart_inds[6][2];
    __shared__ double   delta[3][3];

    const uint32_t ij = blockDim.x * blockIdx.x + threadIdx.x;

    double a_i, a_j, r_i[3], r_j[3], S_ij_00, S1, inv_S1;
    double PB_0, PB_1;
    uint32_t i, j, b0, b1;

    if ((threadIdx.y == 0) && (threadIdx.x == 0))
    {
        d_cart_inds[0][0] = 0; d_cart_inds[0][1] = 0;
        d_cart_inds[1][0] = 0; d_cart_inds[1][1] = 1;
        d_cart_inds[2][0] = 0; d_cart_inds[2][1] = 2;
        d_cart_inds[3][0] = 1; d_cart_inds[3][1] = 1;
        d_cart_inds[4][0] = 1; d_cart_inds[4][1] = 2;
        d_cart_inds[5][0] = 2; d_cart_inds[5][1] = 2;

        delta[0][0] = 1.0; delta[0][1] = 0.0; delta[0][2] = 0.0;
        delta[1][0] = 0.0; delta[1][1] = 1.0; delta[1][2] = 0.0;
        delta[2][0] = 0.0; delta[2][1] = 0.0; delta[2][2] = 1.0;

    }

    ERIs[threadIdx.y][threadIdx.x] = 0.0;

    __syncthreads();

    if (ij < sd_prim_pair_count_local)
    {
        i = sd_first_inds_local[ij];
        j = sd_second_inds_local[ij];

        a_i = s_prim_info[i + s_prim_count * 0];

        r_i[0] = s_prim_info[i + s_prim_count * 2];
        r_i[1] = s_prim_info[i + s_prim_count * 3];
        r_i[2] = s_prim_info[i + s_prim_count * 4];

        a_j = d_prim_info[j / 6 + d_prim_count * 0];

        r_j[0] = d_prim_info[j / 6 + d_prim_count * 2];
        r_j[1] = d_prim_info[j / 6 + d_prim_count * 3];
        r_j[2] = d_prim_info[j / 6 + d_prim_count * 4];

        S1 = a_i + a_j;
        inv_S1 = 1.0 / S1;

        S_ij_00 = sd_pair_data_local[ij];

        b0 = d_cart_inds[j % 6][0];
        b1 = d_cart_inds[j % 6][1];

        PB_0 = (-a_i * inv_S1) * (r_j[b0] - r_i[b0]);
        PB_1 = (-a_i * inv_S1) * (r_j[b1] - r_i[b1]);

    }

    for (uint32_t m = 0; m < (pp_prim_pair_count + TILE_DIM - 1) / TILE_DIM; m++)
    {
        const uint32_t kl = m * TILE_DIM + threadIdx.y;

        if ((ij >= sd_prim_pair_count_local) || (kl >= pp_prim_pair_count) || (fabs(sd_mat_Q_local[ij] * pp_mat_Q[kl] * pp_mat_D[kl]) <= eri_threshold))
        {
            break;
        }

        const auto k = pp_first_inds[kl];
        const auto l = pp_second_inds[kl];

        const auto a_k = p_prim_info[k / 3 + p_prim_count * 0];

        const double r_k[3] = {p_prim_info[k / 3 + p_prim_count * 2],
                               p_prim_info[k / 3 + p_prim_count * 3],
                               p_prim_info[k / 3 + p_prim_count * 4]};

        const auto a_l = p_prim_info[l / 3 + p_prim_count * 0];

        const double r_l[3] = {p_prim_info[l / 3 + p_prim_count * 2],
                               p_prim_info[l / 3 + p_prim_count * 3],
                               p_prim_info[l / 3 + p_prim_count * 4]};

        const auto S_kl_00 = pp_pair_data[kl];

        const auto c0 = k % 3;
        const auto d0 = l % 3;

        // J. Chem. Phys. 84, 3963-3974 (1986)

        const auto S2 = a_k + a_l;

        const auto inv_S2 = 1.0 / S2;
        const auto inv_S4 = 1.0 / (S1 + S2);

        const double PQ[3] = {(a_k * r_k[0] + a_l * r_l[0]) * inv_S2 - (a_i * r_i[0] + a_j * r_j[0]) * inv_S1,
                              (a_k * r_k[1] + a_l * r_l[1]) * inv_S2 - (a_i * r_i[1] + a_j * r_j[1]) * inv_S1,
                              (a_k * r_k[2] + a_l * r_l[2]) * inv_S2 - (a_i * r_i[2] + a_j * r_j[2]) * inv_S1};

        const auto r2_PQ = PQ[0] * PQ[0] + PQ[1] * PQ[1] + PQ[2] * PQ[2];

        const auto Lambda = sqrt(4.0 * S1 * S2 * MATH_CONST_INV_PI * inv_S4);

        double F4_t[5];

        gpu::computeBoysFunction(F4_t, S1 * S2 * inv_S4 * r2_PQ, 4, boys_func_table, boys_func_ft);

        const auto QC_0 = (a_l * inv_S2) * (r_l[c0] - r_k[c0]);
        const auto QD_0 = (-a_k * inv_S2) * (r_l[d0] - r_k[d0]);

        const double eri_ijkl = Lambda * S_ij_00 * S_kl_00 * (

                + F4_t[0] * (

                    0.5 * inv_S1 * (
                        +QC_0*QD_0*delta[b0][b1]
                    )

                    + 0.5 * inv_S2 * (
                        +PB_0*PB_1*delta[c0][d0]
                    )

                    + (
                        +PB_0*PB_1*QC_0*QD_0
                    )

                    + 0.25 * inv_S1 * inv_S2 * (
                        +delta[b0][b1]*delta[c0][d0]
                    )

                )

                + F4_t[1] * (

                    (-0.25) * inv_S1 * inv_S4 * (
                        +delta[b0][b1]*delta[c0][d0]
                    )

                    + (-0.25) * inv_S2 * inv_S4 * (
                        +delta[b0][b1]*delta[c0][d0]
                    )

                    + (-0.5) * S1 * inv_S2 * inv_S4 * (
                        +PB_0*PB_1*delta[c0][d0]
                    )

                    + (-0.5) * S2 * inv_S1 * inv_S4 * (
                        +QC_0*QD_0*delta[b0][b1]
                    )

                    + 0.5 * inv_S4 * (
                        +delta[c0][d0]*(PB_0*PQ[b1] + PB_1*PQ[b0])

                        +PB_0*(QC_0*delta[b1][d0] + QD_0*delta[b1][c0]) + PB_1*(QC_0*delta[b0][d0] + QD_0*delta[b0][c0])

                        +delta[b0][b1]*(-PQ[c0]*QD_0 - PQ[d0]*QC_0)
                    )

                    + S1 * inv_S4 * (
                        +PB_0*PB_1*(-PQ[c0]*QD_0 - PQ[d0]*QC_0)
                    )

                    + S2 * inv_S4 * (
                        +QC_0*QD_0*(PB_0*PQ[b1] + PB_1*PQ[b0])
                    )

                )

                + F4_t[2] * (

                    0.5 * S1 * inv_S4 * inv_S4 * (
                        +delta[c0][d0]*(-PB_0*PQ[b1] - PB_1*PQ[b0])

                        -PB_0*(PQ[c0]*delta[b1][d0] + PQ[d0]*delta[b1][c0]) - PB_1*(PQ[c0]*delta[b0][d0] + PQ[d0]*delta[b0][c0])

                        +PQ[c0]*PQ[d0]*delta[b0][b1]
                    )

                    + 0.5 * S2 * inv_S4 * inv_S4 * (
                        +PQ[b0]*QD_0*delta[b1][c0]

                        +PQ[b1]*QD_0*delta[b0][c0] + QC_0*(PQ[b0]*delta[b1][d0] + PQ[b1]*delta[b0][d0])

                        +delta[b0][b1]*(PQ[c0]*QD_0 + PQ[d0]*QC_0)

                        +PQ[b0]*PQ[b1]*delta[c0][d0]
                    )

                    + S1 * S1 * inv_S4 * inv_S4 * (
                        +PB_0*PB_1*PQ[c0]*PQ[d0]
                    )

                    + S1 * S2 * inv_S4 * inv_S4 * (
                        -(PB_0*PQ[b1] + PB_1*PQ[b0])*(PQ[c0]*QD_0 + PQ[d0]*QC_0)
                    )

                    + S2 * S2 * inv_S4 * inv_S4 * (
                        +PQ[b0]*PQ[b1]*QC_0*QD_0
                    )

                    + 0.25 * inv_S4 * inv_S4 * (
                        +delta[b0][b1]*delta[c0][d0] + delta[b0][c0]*delta[b1][d0] + delta[b0][d0]*delta[b1][c0]
                    )

                )

                + F4_t[3] * (

                    (-0.5) * S1 * S2 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[b0]*PQ[b1]*delta[c0][d0]

                        +PQ[c0]*(PQ[b0]*delta[b1][d0] + PQ[b1]*delta[b0][d0] + PQ[d0]*delta[b0][b1]) + PQ[d0]*(PQ[b0]*delta[b1][c0] + PQ[b1]*delta[b0][c0])
                    )

                    + S1 * S1 * S2 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[c0]*PQ[d0]*(PB_0*PQ[b1] + PB_1*PQ[b0])
                    )

                    + S1 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[b0]*PQ[b1]*(-PQ[c0]*QD_0 - PQ[d0]*QC_0)
                    )

                )

                + F4_t[4] * (

                    S1 * S1 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[b0]*PQ[b1]*PQ[c0]*PQ[d0]
                    )

                )

                );

        // NOTE: doubling for off-diagonal elements of D due to k<=>l symmetry
        //       (static_cast<double>(k != l) + 1.0) == (k == l ? 1.0 : 2.0)
        ERIs[threadIdx.y][threadIdx.x] += eri_ijkl * pp_mat_D[kl] * (static_cast<double>(k != l) + 1.0);

    }

    __syncthreads();

    if ((threadIdx.y == 0) && (ij < sd_prim_pair_count_local))
    {
        double J_ij = 0.0;

        for (uint32_t n = 0; n < TILE_DIM; n++)
        {
            J_ij += ERIs[n][threadIdx.x];
        }

        mat_J[ij] += J_ij;
    }
}

__global__ void __launch_bounds__(TILE_SIZE_J)
computeCoulombFockSDPD(double*         mat_J,
                       const double*   s_prim_info,
                       const uint32_t  s_prim_count,
                       const double*   p_prim_info,
                       const uint32_t  p_prim_count,
                       const double*   d_prim_info,
                       const uint32_t  d_prim_count,
                       const double*   pd_mat_D,
                       const double*   sd_mat_Q_local,
                       const double*   pd_mat_Q,
                       const uint32_t* sd_first_inds_local,
                       const uint32_t* sd_second_inds_local,
                       const double*   sd_pair_data_local,
                       const uint32_t  sd_prim_pair_count_local,
                       const uint32_t* pd_first_inds,
                       const uint32_t* pd_second_inds,
                       const double*   pd_pair_data,
                       const uint32_t  pd_prim_pair_count,
                       const double*   boys_func_table,
                       const double*   boys_func_ft,
                       const double    eri_threshold)
{
    // each thread row scans over [ij|??] and sum up to a primitive J matrix element
    // J. Chem. Theory Comput. 2009, 5, 4, 1004-1015

    __shared__ double   ERIs[TILE_DIM][TILE_DIM + 1];
    __shared__ uint32_t d_cart_inds[6][2];
    __shared__ double   delta[3][3];

    const uint32_t ij = blockDim.x * blockIdx.x + threadIdx.x;

    double a_i, a_j, r_i[3], r_j[3], S_ij_00, S1, inv_S1;
    double PB_0, PB_1;
    uint32_t i, j, b0, b1;

    if ((threadIdx.y == 0) && (threadIdx.x == 0))
    {
        d_cart_inds[0][0] = 0; d_cart_inds[0][1] = 0;
        d_cart_inds[1][0] = 0; d_cart_inds[1][1] = 1;
        d_cart_inds[2][0] = 0; d_cart_inds[2][1] = 2;
        d_cart_inds[3][0] = 1; d_cart_inds[3][1] = 1;
        d_cart_inds[4][0] = 1; d_cart_inds[4][1] = 2;
        d_cart_inds[5][0] = 2; d_cart_inds[5][1] = 2;

        delta[0][0] = 1.0; delta[0][1] = 0.0; delta[0][2] = 0.0;
        delta[1][0] = 0.0; delta[1][1] = 1.0; delta[1][2] = 0.0;
        delta[2][0] = 0.0; delta[2][1] = 0.0; delta[2][2] = 1.0;

    }

    ERIs[threadIdx.y][threadIdx.x] = 0.0;

    __syncthreads();

    if (ij < sd_prim_pair_count_local)
    {
        i = sd_first_inds_local[ij];
        j = sd_second_inds_local[ij];

        a_i = s_prim_info[i + s_prim_count * 0];

        r_i[0] = s_prim_info[i + s_prim_count * 2];
        r_i[1] = s_prim_info[i + s_prim_count * 3];
        r_i[2] = s_prim_info[i + s_prim_count * 4];

        a_j = d_prim_info[j / 6 + d_prim_count * 0];

        r_j[0] = d_prim_info[j / 6 + d_prim_count * 2];
        r_j[1] = d_prim_info[j / 6 + d_prim_count * 3];
        r_j[2] = d_prim_info[j / 6 + d_prim_count * 4];

        S1 = a_i + a_j;
        inv_S1 = 1.0 / S1;

        S_ij_00 = sd_pair_data_local[ij];

        b0 = d_cart_inds[j % 6][0];
        b1 = d_cart_inds[j % 6][1];

        PB_0 = (-a_i * inv_S1) * (r_j[b0] - r_i[b0]);
        PB_1 = (-a_i * inv_S1) * (r_j[b1] - r_i[b1]);

    }

    for (uint32_t m = 0; m < (pd_prim_pair_count + TILE_DIM - 1) / TILE_DIM; m++)
    {
        const uint32_t kl = m * TILE_DIM + threadIdx.y;

        if ((ij >= sd_prim_pair_count_local) || (kl >= pd_prim_pair_count) || (fabs(sd_mat_Q_local[ij] * pd_mat_Q[kl] * pd_mat_D[kl]) <= eri_threshold))
        {
            break;
        }

        const auto k = pd_first_inds[kl];
        const auto l = pd_second_inds[kl];

        const auto a_k = p_prim_info[k / 3 + p_prim_count * 0];

        const double r_k[3] = {p_prim_info[k / 3 + p_prim_count * 2],
                               p_prim_info[k / 3 + p_prim_count * 3],
                               p_prim_info[k / 3 + p_prim_count * 4]};

        const auto a_l = d_prim_info[l / 6 + d_prim_count * 0];

        const double r_l[3] = {d_prim_info[l / 6 + d_prim_count * 2],
                               d_prim_info[l / 6 + d_prim_count * 3],
                               d_prim_info[l / 6 + d_prim_count * 4]};

        const auto S_kl_00 = pd_pair_data[kl];

        const auto c0 = k % 3;
        const auto d0 = d_cart_inds[l % 6][0];
        const auto d1 = d_cart_inds[l % 6][1];

        // J. Chem. Phys. 84, 3963-3974 (1986)

        const auto S2 = a_k + a_l;

        const auto inv_S2 = 1.0 / S2;
        const auto inv_S4 = 1.0 / (S1 + S2);

        const double PQ[3] = {(a_k * r_k[0] + a_l * r_l[0]) * inv_S2 - (a_i * r_i[0] + a_j * r_j[0]) * inv_S1,
                              (a_k * r_k[1] + a_l * r_l[1]) * inv_S2 - (a_i * r_i[1] + a_j * r_j[1]) * inv_S1,
                              (a_k * r_k[2] + a_l * r_l[2]) * inv_S2 - (a_i * r_i[2] + a_j * r_j[2]) * inv_S1};

        const auto r2_PQ = PQ[0] * PQ[0] + PQ[1] * PQ[1] + PQ[2] * PQ[2];

        const auto Lambda = sqrt(4.0 * S1 * S2 * MATH_CONST_INV_PI * inv_S4);

        double F5_t[6];

        gpu::computeBoysFunction(F5_t, S1 * S2 * inv_S4 * r2_PQ, 5, boys_func_table, boys_func_ft);

        const auto QC_0 = (a_l * inv_S2) * (r_l[c0] - r_k[c0]);
        const auto QD_0 = (-a_k * inv_S2) * (r_l[d0] - r_k[d0]);
        const auto QD_1 = (-a_k * inv_S2) * (r_l[d1] - r_k[d1]);

        const double eri_ijkl = Lambda * S_ij_00 * S_kl_00 * (

                + F5_t[0] * (

                    0.25 * inv_S1 * inv_S2 * (
                        +QD_0*delta[b0][b1]*delta[c0][d1]

                        +delta[b0][b1]*(QC_0*delta[d0][d1] + QD_1*delta[c0][d0])
                    )

                    + 0.5 * inv_S1 * (
                        +QC_0*QD_0*QD_1*delta[b0][b1]
                    )

                    + 0.5 * inv_S2 * (
                        +PB_0*PB_1*QC_0*delta[d0][d1]

                        +PB_0*PB_1*(QD_0*delta[c0][d1] + QD_1*delta[c0][d0])
                    )

                    + (
                        +PB_0*PB_1*QC_0*QD_0*QD_1
                    )

                )

                + F5_t[1] * (

                    (-0.25) * inv_S1 * inv_S4 * (
                        +QC_0*delta[b0][b1]*delta[d0][d1]

                        +delta[b0][b1]*(QD_0*delta[c0][d1] + QD_1*delta[c0][d0])
                    )

                    + 0.25 * inv_S2 * inv_S4 * (
                        +PB_0*(delta[b1][c0]*delta[d0][d1] + delta[b1][d0]*delta[c0][d1] + delta[b1][d1]*delta[c0][d0])

                        +PB_1*(delta[b0][c0]*delta[d0][d1] + delta[b0][d0]*delta[c0][d1] + delta[b0][d1]*delta[c0][d0])

                        +delta[b0][b1]*(-delta[c0][d0]*(PQ[d1] + QD_1) - delta[c0][d1]*(PQ[d0] + QD_0) - delta[d0][d1]*(PQ[c0] + QC_0))
                    )

                    + (-0.5) * S1 * inv_S2 * inv_S4 * (
                        +PB_0*PB_1*delta[d0][d1]*(PQ[c0] + QC_0)

                        +PB_0*PB_1*(delta[c0][d0]*(PQ[d1] + QD_1) + delta[c0][d1]*(PQ[d0] + QD_0))
                    )

                    + (-0.5) * S2 * inv_S1 * inv_S4 * (
                        +QC_0*QD_0*QD_1*delta[b0][b1]
                    )

                    + 0.5 * inv_S4 * (
                        +QC_0*delta[d0][d1]*(PB_0*PQ[b1] + PB_1*PQ[b0])

                        +(PB_0*PQ[b1] + PB_1*PQ[b0])*(QD_0*delta[c0][d1] + QD_1*delta[c0][d0])

                        +QC_0*(PB_0*(QD_0*delta[b1][d1] + QD_1*delta[b1][d0]) + PB_1*(QD_0*delta[b0][d1] + QD_1*delta[b0][d0])) + QD_0*QD_1*(PB_0*delta[b1][c0] + PB_1*delta[b0][c0])

                        +delta[b0][b1]*(-PQ[d0]*QC_0*QD_1 - QD_0*(PQ[c0]*QD_1 + PQ[d1]*QC_0))
                    )

                    + S1 * inv_S4 * (
                        +PB_0*PB_1*(-PQ[d0]*QC_0*QD_1 - QD_0*(PQ[c0]*QD_1 + PQ[d1]*QC_0))
                    )

                    + S2 * inv_S4 * (
                        +QC_0*QD_0*QD_1*(PB_0*PQ[b1] + PB_1*PQ[b0])
                    )

                )

                + F5_t[2] * (

                    0.25 * S1 * inv_S2 * inv_S4 * inv_S4 * (
                        +PB_0*(-delta[b1][c0]*delta[d0][d1] - delta[b1][d0]*delta[c0][d1] - delta[b1][d1]*delta[c0][d0])

                        +PB_1*(-delta[b0][c0]*delta[d0][d1] - delta[b0][d0]*delta[c0][d1] - delta[b0][d1]*delta[c0][d0])

                        +delta[b0][b1]*(PQ[c0]*delta[d0][d1] + PQ[d0]*delta[c0][d1] + PQ[d1]*delta[c0][d0])
                    )

                    + 0.25 * inv_S4 * inv_S4 * (
                        +delta[b0][b1]*delta[c0][d1]*(PQ[d0] + QD_0)

                        +QC_0*(delta[b0][d0]*delta[b1][d1] + delta[b0][d1]*delta[b1][d0]) + QD_0*(delta[b0][c0]*delta[b1][d1] + delta[b0][d1]*delta[b1][c0]) + QD_1*(delta[b0][c0]*delta[b1][d0] + delta[b0][d0]*delta[b1][c0])

                        +delta[b0][b1]*(delta[c0][d0]*(PQ[d1] + QD_1) + delta[d0][d1]*(PQ[c0] + QC_0))

                        +PQ[b0]*(delta[b1][c0]*delta[d0][d1] + delta[b1][d0]*delta[c0][d1] + delta[b1][d1]*delta[c0][d0]) + PQ[b1]*(delta[b0][c0]*delta[d0][d1] + delta[b0][d0]*delta[c0][d1] + delta[b0][d1]*delta[c0][d0])
                    )

                    + 0.5 * S1 * S1 * inv_S2 * inv_S4 * inv_S4 * (
                        +PB_0*PB_1*PQ[c0]*delta[d0][d1]

                        +PB_0*PB_1*(PQ[d0]*delta[c0][d1] + PQ[d1]*delta[c0][d0])
                    )

                    + 0.5 * S1 * inv_S4 * inv_S4 * (
                        -delta[d0][d1]*(PQ[c0] + QC_0)*(PB_0*PQ[b1] + PB_1*PQ[b0])

                        -(PB_0*PQ[b1] + PB_1*PQ[b0])*(delta[c0][d0]*(PQ[d1] + QD_1) + delta[c0][d1]*(PQ[d0] + QD_0))

                        -PB_0*(PQ[c0]*(QD_0*delta[b1][d1] + QD_1*delta[b1][d0]) + PQ[d0]*(QC_0*delta[b1][d1] + QD_1*delta[b1][c0]) + PQ[d1]*(QC_0*delta[b1][d0] + QD_0*delta[b1][c0])) - PB_1*(PQ[c0]*(QD_0*delta[b0][d1] + QD_1*delta[b0][d0]) + PQ[d0]*(QC_0*delta[b0][d1] + QD_1*delta[b0][c0]) + PQ[d1]*(QC_0*delta[b0][d0] + QD_0*delta[b0][c0]))

                        +delta[b0][b1]*(PQ[c0]*(PQ[d0]*QD_1 + PQ[d1]*QD_0) + PQ[d0]*PQ[d1]*QC_0)
                    )

                    + 0.5 * S2 * inv_S4 * inv_S4 * (
                        +QC_0*QD_1*(PQ[b0]*delta[b1][d0] + PQ[b1]*delta[b0][d0]) + QD_0*(PQ[b0]*(PQ[b1]*delta[c0][d1] + QC_0*delta[b1][d1] + QD_1*delta[b1][c0]) + PQ[b1]*(QC_0*delta[b0][d1] + QD_1*delta[b0][c0]))

                        +PQ[b0]*PQ[b1]*(QC_0*delta[d0][d1] + QD_1*delta[c0][d0])

                        +delta[b0][b1]*(PQ[d0]*QC_0*QD_1 + QD_0*(PQ[c0]*QD_1 + PQ[d1]*QC_0))
                    )

                    + S1 * S1 * inv_S4 * inv_S4 * (
                        +PB_0*PB_1*(PQ[c0]*(PQ[d0]*QD_1 + PQ[d1]*QD_0) + PQ[d0]*PQ[d1]*QC_0)
                    )

                    + S1 * S2 * inv_S4 * inv_S4 * (
                        -(PB_0*PQ[b1] + PB_1*PQ[b0])*(PQ[d0]*QC_0*QD_1 + QD_0*(PQ[c0]*QD_1 + PQ[d1]*QC_0))
                    )

                    + S2 * S2 * inv_S4 * inv_S4 * (
                        +PQ[b0]*PQ[b1]*QC_0*QD_0*QD_1
                    )

                )

                + F5_t[3] * (

                    (-0.25) * S1 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[b0]*(delta[b1][c0]*delta[d0][d1] + delta[b1][d0]*delta[c0][d1] + delta[b1][d1]*delta[c0][d0])

                        +PQ[b1]*(delta[b0][c0]*delta[d0][d1] + delta[b0][d0]*delta[c0][d1] + delta[b0][d1]*delta[c0][d0]) + PQ[c0]*(delta[b0][b1]*delta[d0][d1] + delta[b0][d0]*delta[b1][d1] + delta[b0][d1]*delta[b1][d0]) + PQ[d0]*(delta[b0][b1]*delta[c0][d1] + delta[b0][c0]*delta[b1][d1] + delta[b0][d1]*delta[b1][c0]) + PQ[d1]*(delta[b0][b1]*delta[c0][d0] + delta[b0][c0]*delta[b1][d0] + delta[b0][d0]*delta[b1][c0])
                    )

                    + 0.5 * S1 * S1 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[c0]*delta[d0][d1]*(PB_0*PQ[b1] + PB_1*PQ[b0])

                        +(PB_0*PQ[b1] + PB_1*PQ[b0])*(PQ[d0]*delta[c0][d1] + PQ[d1]*delta[c0][d0])

                        +PQ[c0]*(PB_0*(PQ[d0]*delta[b1][d1] + PQ[d1]*delta[b1][d0]) + PB_1*(PQ[d0]*delta[b0][d1] + PQ[d1]*delta[b0][d0])) + PQ[d0]*PQ[d1]*(PB_0*delta[b1][c0] + PB_1*delta[b0][c0])

                        -PQ[c0]*PQ[d0]*PQ[d1]*delta[b0][b1]
                    )

                    + (-0.5) * S1 * S2 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[b0]*(PQ[b1]*delta[d0][d1]*(PQ[c0] + QC_0) + PQ[c0]*(QD_0*delta[b1][d1] + QD_1*delta[b1][d0]) + QC_0*(PQ[d0]*delta[b1][d1] + PQ[d1]*delta[b1][d0]) + delta[b1][c0]*(PQ[d0]*QD_1 + PQ[d1]*QD_0)) + PQ[b1]*(PQ[c0]*(QD_0*delta[b0][d1] + QD_1*delta[b0][d0]) + QC_0*(PQ[d0]*delta[b0][d1] + PQ[d1]*delta[b0][d0]) + delta[b0][c0]*(PQ[d0]*QD_1 + PQ[d1]*QD_0))

                        +PQ[b0]*PQ[b1]*(delta[c0][d0]*(PQ[d1] + QD_1) + delta[c0][d1]*(PQ[d0] + QD_0))

                        +delta[b0][b1]*(PQ[c0]*(PQ[d0]*QD_1 + PQ[d1]*QD_0) + PQ[d0]*PQ[d1]*QC_0)
                    )

                    + S1 * S1 * S1 * inv_S4 * inv_S4 * inv_S4 * (
                        -PB_0*PB_1*PQ[c0]*PQ[d0]*PQ[d1]
                    )

                    + S1 * S1 * S2 * inv_S4 * inv_S4 * inv_S4 * (
                        +(PB_0*PQ[b1] + PB_1*PQ[b0])*(PQ[c0]*(PQ[d0]*QD_1 + PQ[d1]*QD_0) + PQ[d0]*PQ[d1]*QC_0)
                    )

                    + S1 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[b0]*PQ[b1]*(-PQ[d0]*QC_0*QD_1 - QD_0*(PQ[c0]*QD_1 + PQ[d1]*QC_0))
                    )

                )

                + F5_t[4] * (

                    S1 * S1 * S1 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[c0]*PQ[d0]*PQ[d1]*(-PB_0*PQ[b1] - PB_1*PQ[b0])
                    )

                    + S1 * S1 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[b0]*PQ[b1]*(PQ[c0]*(PQ[d0]*QD_1 + PQ[d1]*QD_0) + PQ[d0]*PQ[d1]*QC_0)
                    )

                    + 0.5 * S1 * S1 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[b0]*PQ[b1]*PQ[c0]*delta[d0][d1]

                        +PQ[d0]*(PQ[b0]*(PQ[b1]*delta[c0][d1] + PQ[c0]*delta[b1][d1] + PQ[d1]*delta[b1][c0]) + PQ[b1]*(PQ[c0]*delta[b0][d1] + PQ[d1]*delta[b0][c0])) + PQ[d1]*(PQ[b0]*(PQ[b1]*delta[c0][d0] + PQ[c0]*delta[b1][d0]) + PQ[c0]*(PQ[b1]*delta[b0][d0] + PQ[d0]*delta[b0][b1]))
                    )

                )

                + F5_t[5] * (

                    (-1.0) * S1 * S1 * S1 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[b0]*PQ[b1]*PQ[c0]*PQ[d0]*PQ[d1]
                    )

                )

                );

        // NOTE: doubling for off-diagonal elements of D due to k<=>l symmetry
        ERIs[threadIdx.y][threadIdx.x] += eri_ijkl * pd_mat_D[kl] * 2.0;

    }

    __syncthreads();

    if ((threadIdx.y == 0) && (ij < sd_prim_pair_count_local))
    {
        double J_ij = 0.0;

        for (uint32_t n = 0; n < TILE_DIM; n++)
        {
            J_ij += ERIs[n][threadIdx.x];
        }

        mat_J[ij] += J_ij;
    }
}

__global__ void __launch_bounds__(TILE_SIZE_J)
computeCoulombFockSDDD(double*         mat_J,
                       const double*   s_prim_info,
                       const uint32_t  s_prim_count,
                       const double*   d_prim_info,
                       const uint32_t  d_prim_count,
                       const double*   dd_mat_D,
                       const double*   sd_mat_Q_local,
                       const double*   dd_mat_Q,
                       const uint32_t* sd_first_inds_local,
                       const uint32_t* sd_second_inds_local,
                       const double*   sd_pair_data_local,
                       const uint32_t  sd_prim_pair_count_local,
                       const uint32_t* dd_first_inds,
                       const uint32_t* dd_second_inds,
                       const double*   dd_pair_data,
                       const uint32_t  dd_prim_pair_count,
                       const double*   boys_func_table,
                       const double*   boys_func_ft,
                       const double    eri_threshold)
{
    // each thread row scans over [ij|??] and sum up to a primitive J matrix element
    // J. Chem. Theory Comput. 2009, 5, 4, 1004-1015

    __shared__ double   ERIs[TILE_DIM][TILE_DIM + 1];
    __shared__ uint32_t d_cart_inds[6][2];
    __shared__ double   delta[3][3];

    const uint32_t ij = blockDim.x * blockIdx.x + threadIdx.x;

    double a_i, a_j, r_i[3], r_j[3], S_ij_00, S1, inv_S1;
    double PB_0, PB_1;
    uint32_t i, j, b0, b1;

    if ((threadIdx.y == 0) && (threadIdx.x == 0))
    {
        d_cart_inds[0][0] = 0; d_cart_inds[0][1] = 0;
        d_cart_inds[1][0] = 0; d_cart_inds[1][1] = 1;
        d_cart_inds[2][0] = 0; d_cart_inds[2][1] = 2;
        d_cart_inds[3][0] = 1; d_cart_inds[3][1] = 1;
        d_cart_inds[4][0] = 1; d_cart_inds[4][1] = 2;
        d_cart_inds[5][0] = 2; d_cart_inds[5][1] = 2;

        delta[0][0] = 1.0; delta[0][1] = 0.0; delta[0][2] = 0.0;
        delta[1][0] = 0.0; delta[1][1] = 1.0; delta[1][2] = 0.0;
        delta[2][0] = 0.0; delta[2][1] = 0.0; delta[2][2] = 1.0;

    }

    ERIs[threadIdx.y][threadIdx.x] = 0.0;

    __syncthreads();

    if (ij < sd_prim_pair_count_local)
    {
        i = sd_first_inds_local[ij];
        j = sd_second_inds_local[ij];

        a_i = s_prim_info[i + s_prim_count * 0];

        r_i[0] = s_prim_info[i + s_prim_count * 2];
        r_i[1] = s_prim_info[i + s_prim_count * 3];
        r_i[2] = s_prim_info[i + s_prim_count * 4];

        a_j = d_prim_info[j / 6 + d_prim_count * 0];

        r_j[0] = d_prim_info[j / 6 + d_prim_count * 2];
        r_j[1] = d_prim_info[j / 6 + d_prim_count * 3];
        r_j[2] = d_prim_info[j / 6 + d_prim_count * 4];

        S1 = a_i + a_j;
        inv_S1 = 1.0 / S1;

        S_ij_00 = sd_pair_data_local[ij];

        b0 = d_cart_inds[j % 6][0];
        b1 = d_cart_inds[j % 6][1];

        PB_0 = (-a_i * inv_S1) * (r_j[b0] - r_i[b0]);
        PB_1 = (-a_i * inv_S1) * (r_j[b1] - r_i[b1]);

    }

    for (uint32_t m = 0; m < (dd_prim_pair_count + TILE_DIM - 1) / TILE_DIM; m++)
    {
        const uint32_t kl = m * TILE_DIM + threadIdx.y;

        if ((ij >= sd_prim_pair_count_local) || (kl >= dd_prim_pair_count) || (fabs(sd_mat_Q_local[ij] * dd_mat_Q[kl] * dd_mat_D[kl]) <= eri_threshold))
        {
            break;
        }

        const auto k = dd_first_inds[kl];
        const auto l = dd_second_inds[kl];

        const auto a_k = d_prim_info[k / 6 + d_prim_count * 0];

        const double r_k[3] = {d_prim_info[k / 6 + d_prim_count * 2],
                               d_prim_info[k / 6 + d_prim_count * 3],
                               d_prim_info[k / 6 + d_prim_count * 4]};

        const auto a_l = d_prim_info[l / 6 + d_prim_count * 0];

        const double r_l[3] = {d_prim_info[l / 6 + d_prim_count * 2],
                               d_prim_info[l / 6 + d_prim_count * 3],
                               d_prim_info[l / 6 + d_prim_count * 4]};

        const auto S_kl_00 = dd_pair_data[kl];

        const auto c0 = d_cart_inds[k % 6][0];
        const auto c1 = d_cart_inds[k % 6][1];
        const auto d0 = d_cart_inds[l % 6][0];
        const auto d1 = d_cart_inds[l % 6][1];

        // J. Chem. Phys. 84, 3963-3974 (1986)

        const auto S2 = a_k + a_l;

        const auto inv_S2 = 1.0 / S2;
        const auto inv_S4 = 1.0 / (S1 + S2);

        const double PQ[3] = {(a_k * r_k[0] + a_l * r_l[0]) * inv_S2 - (a_i * r_i[0] + a_j * r_j[0]) * inv_S1,
                              (a_k * r_k[1] + a_l * r_l[1]) * inv_S2 - (a_i * r_i[1] + a_j * r_j[1]) * inv_S1,
                              (a_k * r_k[2] + a_l * r_l[2]) * inv_S2 - (a_i * r_i[2] + a_j * r_j[2]) * inv_S1};

        const auto r2_PQ = PQ[0] * PQ[0] + PQ[1] * PQ[1] + PQ[2] * PQ[2];

        const auto Lambda = sqrt(4.0 * S1 * S2 * MATH_CONST_INV_PI * inv_S4);

        double F6_t[7];

        gpu::computeBoysFunction(F6_t, S1 * S2 * inv_S4 * r2_PQ, 6, boys_func_table, boys_func_ft);

        const auto QC_0 = (a_l * inv_S2) * (r_l[c0] - r_k[c0]);
        const auto QC_1 = (a_l * inv_S2) * (r_l[c1] - r_k[c1]);
        const auto QD_0 = (-a_k * inv_S2) * (r_l[d0] - r_k[d0]);
        const auto QD_1 = (-a_k * inv_S2) * (r_l[d1] - r_k[d1]);

        const double eri_ijkl = Lambda * S_ij_00 * S_kl_00 * (

                + F6_t[0] * (

                    0.25 * inv_S1 * inv_S2 * (
                        +QC_0*QD_0*delta[b0][b1]*delta[c1][d1]

                        +delta[b0][b1]*(QC_1*(QC_0*delta[d0][d1] + QD_0*delta[c0][d1] + QD_1*delta[c0][d0]) + QD_1*(QC_0*delta[c1][d0] + QD_0*delta[c0][c1]))
                    )

                    + 0.25 * inv_S2 * inv_S2 * (
                        +PB_0*PB_1*(delta[c0][c1]*delta[d0][d1] + delta[c0][d0]*delta[c1][d1] + delta[c0][d1]*delta[c1][d0])
                    )

                    + 0.5 * inv_S1 * (
                        +QC_0*QC_1*QD_0*QD_1*delta[b0][b1]
                    )

                    + 0.5 * inv_S2 * (
                        +PB_0*PB_1*QC_0*QC_1*delta[d0][d1]

                        +PB_0*PB_1*(QD_0*(QC_0*delta[c1][d1] + QC_1*delta[c0][d1] + QD_1*delta[c0][c1]) + QD_1*(QC_0*delta[c1][d0] + QC_1*delta[c0][d0]))
                    )

                    + (
                        +PB_0*PB_1*QC_0*QC_1*QD_0*QD_1
                    )

                    + 0.125 * inv_S1 * inv_S2 * inv_S2 * (
                        +delta[b0][b1]*(delta[c0][c1]*delta[d0][d1] + delta[c0][d0]*delta[c1][d1] + delta[c0][d1]*delta[c1][d0])
                    )

                )

                + F6_t[1] * (

                    (-0.125) * inv_S1 * inv_S2 * inv_S4 * (
