                        +(PB_0*PQ[a0]*PQ[b1] + PQ[b0]*(PA_0*PQ[b1] + PB_1*PQ[a0]))*(PQ[c0]*QD_0*(PQ[c1]*QD_1 + PQ[d1]*QC_1) + PQ[c1]*QC_0*(PQ[d0]*QD_1 + PQ[d1]*QD_0) + PQ[d0]*QC_1*(PQ[c0]*QD_1 + PQ[d1]*QC_0))

                    )


                );

        // NOTE: doubling for off-diagonal elements of D due to k<=>l symmetry
        //       (static_cast<double>(k != l) + 1.0) == (k == l ? 1.0 : 2.0)
        ERIs[threadIdx.y][threadIdx.x] += eri_ijkl * dd_mat_D[kl] * (static_cast<double>(k != l) + 1.0);

    }

    __syncthreads();

    if ((threadIdx.y == 0) && (ij < pd_prim_pair_count_local))
    {
        double J_ij = 0.0;

        for (uint32_t n = 0; n < TILE_DIM; n++)
        {
            J_ij += ERIs[n][threadIdx.x];
        }

        mat_J[ij] += J_ij;
    }
}

__global__ void __launch_bounds__(TILE_SIZE_J)
computeCoulombFockPDDD6(double*         mat_J,
                       const double*   p_prim_info,
                       const uint32_t  p_prim_count,
                       const double*   d_prim_info,
                       const uint32_t  d_prim_count,
                       const double*   dd_mat_D,
                       const double*   pd_mat_Q_local,
                       const double*   dd_mat_Q,
                       const uint32_t* pd_first_inds_local,
                       const uint32_t* pd_second_inds_local,
                       const double*   pd_pair_data_local,
                       const uint32_t  pd_prim_pair_count_local,
                       const uint32_t* dd_first_inds,
                       const uint32_t* dd_second_inds,
                       const double*   dd_pair_data,
                       const uint32_t  dd_prim_pair_count,
                       const double*   boys_func_table,
                       const double*   boys_func_ft,
                       const double    eri_threshold)
{
    // each thread row scans over [ij|??] and sum up to a primitive J matrix element
    // J. Chem. Theory Comput. 2009, 5, 4, 1004-1015

    __shared__ double   ERIs[TILE_DIM][TILE_DIM + 1];
    __shared__ uint32_t d_cart_inds[6][2];
    __shared__ double   delta[3][3];

    const uint32_t ij = blockDim.x * blockIdx.x + threadIdx.x;

    double a_i, a_j, r_i[3], r_j[3], S_ij_00, S1, inv_S1;
    double PA_0, PB_0, PB_1;
    uint32_t i, j, a0, b0, b1;

    if ((threadIdx.y == 0) && (threadIdx.x == 0))
    {
        d_cart_inds[0][0] = 0; d_cart_inds[0][1] = 0;
        d_cart_inds[1][0] = 0; d_cart_inds[1][1] = 1;
        d_cart_inds[2][0] = 0; d_cart_inds[2][1] = 2;
        d_cart_inds[3][0] = 1; d_cart_inds[3][1] = 1;
        d_cart_inds[4][0] = 1; d_cart_inds[4][1] = 2;
        d_cart_inds[5][0] = 2; d_cart_inds[5][1] = 2;

        delta[0][0] = 1.0; delta[0][1] = 0.0; delta[0][2] = 0.0;
        delta[1][0] = 0.0; delta[1][1] = 1.0; delta[1][2] = 0.0;
        delta[2][0] = 0.0; delta[2][1] = 0.0; delta[2][2] = 1.0;

    }

    ERIs[threadIdx.y][threadIdx.x] = 0.0;

    __syncthreads();

    if (ij < pd_prim_pair_count_local)
    {
        i = pd_first_inds_local[ij];
        j = pd_second_inds_local[ij];

        a_i = p_prim_info[i / 3 + p_prim_count * 0];

        r_i[0] = p_prim_info[i / 3 + p_prim_count * 2];
        r_i[1] = p_prim_info[i / 3 + p_prim_count * 3];
        r_i[2] = p_prim_info[i / 3 + p_prim_count * 4];

        a_j = d_prim_info[j / 6 + d_prim_count * 0];

        r_j[0] = d_prim_info[j / 6 + d_prim_count * 2];
        r_j[1] = d_prim_info[j / 6 + d_prim_count * 3];
        r_j[2] = d_prim_info[j / 6 + d_prim_count * 4];

        S1 = a_i + a_j;
        inv_S1 = 1.0 / S1;

        S_ij_00 = pd_pair_data_local[ij];

        a0 = i % 3;
        b0 = d_cart_inds[j % 6][0];
        b1 = d_cart_inds[j % 6][1];

        PA_0 = (a_j  * inv_S1) * (r_j[a0] - r_i[a0]);
        PB_0 = (-a_i * inv_S1) * (r_j[b0] - r_i[b0]);
        PB_1 = (-a_i * inv_S1) * (r_j[b1] - r_i[b1]);

    }

    for (uint32_t m = 0; m < (dd_prim_pair_count + TILE_DIM - 1) / TILE_DIM; m++)
    {
        const uint32_t kl = m * TILE_DIM + threadIdx.y;

        if ((ij >= pd_prim_pair_count_local) || (kl >= dd_prim_pair_count) || (fabs(pd_mat_Q_local[ij] * dd_mat_Q[kl] * dd_mat_D[kl]) <= eri_threshold))
        {
            break;
        }

        const auto k = dd_first_inds[kl];
        const auto l = dd_second_inds[kl];

        const auto a_k = d_prim_info[k / 6 + d_prim_count * 0];

        const double r_k[3] = {d_prim_info[k / 6 + d_prim_count * 2],
                               d_prim_info[k / 6 + d_prim_count * 3],
                               d_prim_info[k / 6 + d_prim_count * 4]};

        const auto a_l = d_prim_info[l / 6 + d_prim_count * 0];

        const double r_l[3] = {d_prim_info[l / 6 + d_prim_count * 2],
                               d_prim_info[l / 6 + d_prim_count * 3],
                               d_prim_info[l / 6 + d_prim_count * 4]};

        const auto S_kl_00 = dd_pair_data[kl];

        const auto c0 = d_cart_inds[k % 6][0];
        const auto c1 = d_cart_inds[k % 6][1];
        const auto d0 = d_cart_inds[l % 6][0];
        const auto d1 = d_cart_inds[l % 6][1];

        // J. Chem. Phys. 84, 3963-3974 (1986)

        const auto S2 = a_k + a_l;

        const auto inv_S2 = 1.0 / S2;
        const auto inv_S4 = 1.0 / (S1 + S2);

        const double PQ[3] = {(a_k * r_k[0] + a_l * r_l[0]) * inv_S2 - (a_i * r_i[0] + a_j * r_j[0]) * inv_S1,
                              (a_k * r_k[1] + a_l * r_l[1]) * inv_S2 - (a_i * r_i[1] + a_j * r_j[1]) * inv_S1,
                              (a_k * r_k[2] + a_l * r_l[2]) * inv_S2 - (a_i * r_i[2] + a_j * r_j[2]) * inv_S1};

        const auto r2_PQ = PQ[0] * PQ[0] + PQ[1] * PQ[1] + PQ[2] * PQ[2];

        const auto Lambda = sqrt(4.0 * S1 * S2 * MATH_CONST_INV_PI * inv_S4);

        double F7_t[8];

        gpu::computeBoysFunction(F7_t, S1 * S2 * inv_S4 * r2_PQ, 7, boys_func_table, boys_func_ft);

        const auto QC_0 = (a_l * inv_S2) * (r_l[c0] - r_k[c0]);
        const auto QC_1 = (a_l * inv_S2) * (r_l[c1] - r_k[c1]);
        const auto QD_0 = (-a_k * inv_S2) * (r_l[d0] - r_k[d0]);
        const auto QD_1 = (-a_k * inv_S2) * (r_l[d1] - r_k[d1]);

        const double eri_ijkl = Lambda * S_ij_00 * S_kl_00 * (

                    + F7_t[4] * S1 * S2 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (

                        -PQ[a0]*PQ[b0]*PQ[b1]*(QC_0*QD_1*(PQ[c1]*QD_0 + PQ[d0]*QC_1) + QC_1*QD_0*(PQ[c0]*QD_1 + PQ[d1]*QC_0))

                    )

                    + F7_t[5] * 0.5 * S1 * S1 * S1 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (

                        -(PB_0*PQ[a0]*PQ[b1] + PQ[b0]*(PA_0*PQ[b1] + PB_1*PQ[a0]))*(PQ[c0]*(PQ[c1]*delta[d0][d1] + PQ[d0]*delta[c1][d1] + PQ[d1]*delta[c1][d0]) + PQ[c1]*(PQ[d0]*delta[c0][d1] + PQ[d1]*delta[c0][d0]) + PQ[d0]*PQ[d1]*delta[c0][c1])

                        -PQ[c0]*PQ[c1]*(PA_0*(PQ[b0]*(PQ[d0]*delta[b1][d1] + PQ[d1]*delta[b1][d0]) + PQ[b1]*(PQ[d0]*delta[b0][d1] + PQ[d1]*delta[b0][d0])) + PB_0*(PQ[a0]*(PQ[d0]*delta[b1][d1] + PQ[d1]*delta[b1][d0]) + PQ[b1]*(PQ[d0]*delta[a0][d1] + PQ[d1]*delta[a0][d0])) + PB_1*(PQ[a0]*(PQ[d0]*delta[b0][d1] + PQ[d1]*delta[b0][d0]) + PQ[b0]*(PQ[d0]*delta[a0][d1] + PQ[d1]*delta[a0][d0]))) - PQ[d0]*PQ[d1]*(PA_0*(PQ[b0]*(PQ[c0]*delta[b1][c1] + PQ[c1]*delta[b1][c0]) + PQ[b1]*(PQ[c0]*delta[b0][c1] + PQ[c1]*delta[b0][c0])) + PB_0*(PQ[a0]*(PQ[c0]*delta[b1][c1] + PQ[c1]*delta[b1][c0]) + PQ[b1]*(PQ[c0]*delta[a0][c1] + PQ[c1]*delta[a0][c0])) + PB_1*(PQ[a0]*(PQ[c0]*delta[b0][c1] + PQ[c1]*delta[b0][c0]) + PQ[b0]*(PQ[c0]*delta[a0][c1] + PQ[c1]*delta[a0][c0])))

                        +PQ[c0]*PQ[c1]*PQ[d0]*PQ[d1]*(-PA_0*delta[b0][b1] - PB_0*delta[a0][b1] - PB_1*delta[a0][b0] + PQ[a0]*delta[b0][b1] + PQ[b0]*delta[a0][b1] + PQ[b1]*delta[a0][b0])

                    )

                    + F7_t[5] * 0.5 * S1 * S1 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (

                        +PQ[a0]*PQ[b0]*PQ[b1]*(PQ[c0]*(delta[c1][d0]*(PQ[d1] + QD_1) + delta[c1][d1]*(PQ[d0] + QD_0) + delta[d0][d1]*(PQ[c1] + QC_1)) + PQ[c1]*(QC_0*delta[d0][d1] + delta[c0][d0]*(PQ[d1] + QD_1) + delta[c0][d1]*(PQ[d0] + QD_0)) + PQ[d0]*(QC_0*delta[c1][d1] + QC_1*delta[c0][d1] + delta[c0][c1]*(PQ[d1] + QD_1)) + PQ[d1]*(QC_0*delta[c1][d0] + QC_1*delta[c0][d0] + QD_0*delta[c0][c1]))

                        +PQ[a0]*(PQ[b0]*(PQ[c0]*(PQ[c1]*(QD_0*delta[b1][d1] + QD_1*delta[b1][d0]) + PQ[d0]*(QC_1*delta[b1][d1] + QD_1*delta[b1][c1]) + PQ[d1]*(QC_1*delta[b1][d0] + QD_0*delta[b1][c1])) + PQ[c1]*(PQ[d0]*(QC_0*delta[b1][d1] + QD_1*delta[b1][c0]) + PQ[d1]*(QC_0*delta[b1][d0] + QD_0*delta[b1][c0]))) + PQ[b1]*(PQ[c0]*(PQ[c1]*(QD_0*delta[b0][d1] + QD_1*delta[b0][d0]) + PQ[d0]*(QC_1*delta[b0][d1] + QD_1*delta[b0][c1]) + PQ[d1]*(QC_1*delta[b0][d0] + QD_0*delta[b0][c1])) + PQ[c1]*(PQ[d0]*(QC_0*delta[b0][d1] + QD_1*delta[b0][c0]) + PQ[d1]*(QC_0*delta[b0][d0] + QD_0*delta[b0][c0]))) + PQ[d0]*PQ[d1]*(PQ[b0]*(QC_0*delta[b1][c1] + QC_1*delta[b1][c0]) + PQ[b1]*(QC_0*delta[b0][c1] + QC_1*delta[b0][c0]))) + PQ[b0]*PQ[b1]*(PQ[c0]*(PQ[c1]*(QD_0*delta[a0][d1] + QD_1*delta[a0][d0]) + PQ[d0]*(QC_1*delta[a0][d1] + QD_1*delta[a0][c1]) + PQ[d1]*(QC_1*delta[a0][d0] + QD_0*delta[a0][c1])) + PQ[c1]*(PQ[d0]*(QC_0*delta[a0][d1] + QD_1*delta[a0][c0]) + PQ[d1]*(QC_0*delta[a0][d0] + QD_0*delta[a0][c0])) + PQ[d0]*PQ[d1]*(QC_0*delta[a0][c1] + QC_1*delta[a0][c0]))

                        +(PQ[c0]*PQ[c1]*(PQ[d0]*QD_1 + PQ[d1]*QD_0) + PQ[d0]*PQ[d1]*(PQ[c0]*QC_1 + PQ[c1]*QC_0))*(PQ[a0]*delta[b0][b1] + PQ[b0]*delta[a0][b1] + PQ[b1]*delta[a0][b0])

                    )

                    + F7_t[5] * S1 * S1 * S1 * S1 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (

                        +PQ[c0]*PQ[c1]*PQ[d0]*PQ[d1]*(PA_0*(PB_0*PQ[b1] + PB_1*PQ[b0]) + PB_0*PB_1*PQ[a0])

                    )

                    + F7_t[5] * S1 * S1 * S1 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (

                        -(PB_0*PQ[a0]*PQ[b1] + PQ[b0]*(PA_0*PQ[b1] + PB_1*PQ[a0]))*(PQ[c0]*PQ[c1]*(PQ[d0]*QD_1 + PQ[d1]*QD_0) + PQ[d0]*PQ[d1]*(PQ[c0]*QC_1 + PQ[c1]*QC_0))

                    )

                    + F7_t[5] * S1 * S1 * S2 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (

                        +PQ[a0]*PQ[b0]*PQ[b1]*(PQ[c0]*QD_0*(PQ[c1]*QD_1 + PQ[d1]*QC_1) + PQ[c1]*QC_0*(PQ[d0]*QD_1 + PQ[d1]*QD_0) + PQ[d0]*QC_1*(PQ[c0]*QD_1 + PQ[d1]*QC_0))

                    )

                    + F7_t[5] * 0.25 * S1 * S1 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (

                        +PQ[a0]*(PQ[b0]*(PQ[b1]*(delta[c0][c1]*delta[d0][d1] + delta[c0][d0]*delta[c1][d1] + delta[c0][d1]*delta[c1][d0]) + PQ[c0]*(delta[b1][c1]*delta[d0][d1] + delta[b1][d0]*delta[c1][d1] + delta[b1][d1]*delta[c1][d0]) + PQ[c1]*(delta[b1][c0]*delta[d0][d1] + delta[b1][d0]*delta[c0][d1] + delta[b1][d1]*delta[c0][d0]) + PQ[d0]*(delta[b1][c0]*delta[c1][d1] + delta[b1][c1]*delta[c0][d1] + delta[b1][d1]*delta[c0][c1]) + PQ[d1]*(delta[b1][c0]*delta[c1][d0] + delta[b1][c1]*delta[c0][d0] + delta[b1][d0]*delta[c0][c1])) + PQ[d1]*(PQ[b1]*(delta[b0][c0]*delta[c1][d0] + delta[b0][c1]*delta[c0][d0] + delta[b0][d0]*delta[c0][c1]) + PQ[c0]*(delta[b0][b1]*delta[c1][d0] + delta[b0][c1]*delta[b1][d0] + delta[b0][d0]*delta[b1][c1]) + PQ[c1]*(delta[b0][b1]*delta[c0][d0] + delta[b0][c0]*delta[b1][d0] + delta[b0][d0]*delta[b1][c0]) + PQ[d0]*(delta[b0][b1]*delta[c0][c1] + delta[b0][c0]*delta[b1][c1] + delta[b0][c1]*delta[b1][c0]))) + PQ[b0]*PQ[d1]*(PQ[b1]*(delta[a0][c0]*delta[c1][d0] + delta[a0][c1]*delta[c0][d0] + delta[a0][d0]*delta[c0][c1]) + PQ[c0]*(delta[a0][b1]*delta[c1][d0] + delta[a0][c1]*delta[b1][d0] + delta[a0][d0]*delta[b1][c1]) + PQ[c1]*(delta[a0][b1]*delta[c0][d0] + delta[a0][c0]*delta[b1][d0] + delta[a0][d0]*delta[b1][c0]) + PQ[d0]*(delta[a0][b1]*delta[c0][c1] + delta[a0][c0]*delta[b1][c1] + delta[a0][c1]*delta[b1][c0])) + PQ[b1]*(PQ[c0]*(PQ[a0]*(delta[b0][c1]*delta[d0][d1] + delta[b0][d0]*delta[c1][d1] + delta[b0][d1]*delta[c1][d0]) + PQ[b0]*(delta[a0][c1]*delta[d0][d1] + delta[a0][d0]*delta[c1][d1] + delta[a0][d1]*delta[c1][d0]) + PQ[c1]*(delta[a0][b0]*delta[d0][d1] + delta[a0][d0]*delta[b0][d1] + delta[a0][d1]*delta[b0][d0]) + PQ[d0]*(delta[a0][b0]*delta[c1][d1] + delta[a0][c1]*delta[b0][d1] + delta[a0][d1]*delta[b0][c1]) + PQ[d1]*(delta[a0][b0]*delta[c1][d0] + delta[a0][c1]*delta[b0][d0] + delta[a0][d0]*delta[b0][c1])) + PQ[c1]*(PQ[a0]*(delta[b0][c0]*delta[d0][d1] + delta[b0][d0]*delta[c0][d1] + delta[b0][d1]*delta[c0][d0]) + PQ[b0]*(delta[a0][c0]*delta[d0][d1] + delta[a0][d0]*delta[c0][d1] + delta[a0][d1]*delta[c0][d0]) + PQ[d1]*(delta[a0][b0]*delta[c0][d0] + delta[a0][c0]*delta[b0][d0] + delta[a0][d0]*delta[b0][c0])) + PQ[d0]*(PQ[a0]*(delta[b0][c0]*delta[c1][d1] + delta[b0][c1]*delta[c0][d1] + delta[b0][d1]*delta[c0][c1]) + PQ[b0]*(delta[a0][c0]*delta[c1][d1] + delta[a0][c1]*delta[c0][d1] + delta[a0][d1]*delta[c0][c1]) + PQ[d1]*(delta[a0][b0]*delta[c0][c1] + delta[a0][c0]*delta[b0][c1] + delta[a0][c1]*delta[b0][c0]))) + PQ[c0]*(PQ[c1]*(PQ[a0]*(delta[b0][b1]*delta[d0][d1] + delta[b0][d0]*delta[b1][d1] + delta[b0][d1]*delta[b1][d0]) + PQ[b0]*(delta[a0][b1]*delta[d0][d1] + delta[a0][d0]*delta[b1][d1] + delta[a0][d1]*delta[b1][d0]) + PQ[d1]*(delta[a0][b0]*delta[b1][d0] + delta[a0][b1]*delta[b0][d0] + delta[a0][d0]*delta[b0][b1])) + PQ[d0]*(PQ[a0]*(delta[b0][b1]*delta[c1][d1] + delta[b0][c1]*delta[b1][d1] + delta[b0][d1]*delta[b1][c1]) + PQ[b0]*(delta[a0][b1]*delta[c1][d1] + delta[a0][c1]*delta[b1][d1] + delta[a0][d1]*delta[b1][c1]) + PQ[d1]*(delta[a0][b0]*delta[b1][c1] + delta[a0][b1]*delta[b0][c1] + delta[a0][c1]*delta[b0][b1]))) + PQ[c1]*PQ[d0]*(PQ[a0]*(delta[b0][b1]*delta[c0][d1] + delta[b0][c0]*delta[b1][d1] + delta[b0][d1]*delta[b1][c0]) + PQ[b0]*(delta[a0][b1]*delta[c0][d1] + delta[a0][c0]*delta[b1][d1] + delta[a0][d1]*delta[b1][c0]) + PQ[b1]*(delta[a0][b0]*delta[c0][d1] + delta[a0][c0]*delta[b0][d1] + delta[a0][d1]*delta[b0][c0]) + PQ[c0]*(delta[a0][b0]*delta[b1][d1] + delta[a0][b1]*delta[b0][d1] + delta[a0][d1]*delta[b0][b1]) + PQ[d1]*(delta[a0][b0]*delta[b1][c0] + delta[a0][b1]*delta[b0][c0] + delta[a0][c0]*delta[b0][b1]))

                    )

                    + F7_t[6] * (-0.5) * S1 * S1 * S1 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (

                        +PQ[a0]*PQ[d0]*PQ[d1]*(PQ[b0]*(PQ[b1]*delta[c0][c1] + PQ[c0]*delta[b1][c1] + PQ[c1]*delta[b1][c0]) + PQ[b1]*(PQ[c0]*delta[b0][c1] + PQ[c1]*delta[b0][c0])) + PQ[b0]*PQ[b1]*(PQ[a0]*(PQ[c0]*(PQ[c1]*delta[d0][d1] + PQ[d0]*delta[c1][d1] + PQ[d1]*delta[c1][d0]) + PQ[c1]*(PQ[d0]*delta[c0][d1] + PQ[d1]*delta[c0][d0])) + PQ[c0]*PQ[c1]*(PQ[d0]*delta[a0][d1] + PQ[d1]*delta[a0][d0]) + PQ[d0]*PQ[d1]*(PQ[c0]*delta[a0][c1] + PQ[c1]*delta[a0][c0])) + PQ[c0]*PQ[c1]*(PQ[a0]*(PQ[b0]*(PQ[d0]*delta[b1][d1] + PQ[d1]*delta[b1][d0]) + PQ[b1]*(PQ[d0]*delta[b0][d1] + PQ[d1]*delta[b0][d0])) + PQ[d0]*PQ[d1]*(PQ[a0]*delta[b0][b1] + PQ[b0]*delta[a0][b1] + PQ[b1]*delta[a0][b0]))

                    )

                    + F7_t[6] * S1 * S1 * S1 * S1 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (

                        +PQ[c0]*PQ[c1]*PQ[d0]*PQ[d1]*(PB_0*PQ[a0]*PQ[b1] + PQ[b0]*(PA_0*PQ[b1] + PB_1*PQ[a0]))

                    )

                    + F7_t[6] * S1 * S1 * S1 * S2 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (

                        -PQ[a0]*PQ[b0]*PQ[b1]*(PQ[c0]*PQ[c1]*(PQ[d0]*QD_1 + PQ[d1]*QD_0) + PQ[d0]*PQ[d1]*(PQ[c0]*QC_1 + PQ[c1]*QC_0))

                    )

                    + F7_t[7] * S1 * S1 * S1 * S1 * S2 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (

                        +PQ[a0]*PQ[b0]*PQ[b1]*PQ[c0]*PQ[c1]*PQ[d0]*PQ[d1]

                    )


                );

        // NOTE: doubling for off-diagonal elements of D due to k<=>l symmetry
        //       (static_cast<double>(k != l) + 1.0) == (k == l ? 1.0 : 2.0)
        ERIs[threadIdx.y][threadIdx.x] += eri_ijkl * dd_mat_D[kl] * (static_cast<double>(k != l) + 1.0);

    }

    __syncthreads();

    if ((threadIdx.y == 0) && (ij < pd_prim_pair_count_local))
    {
        double J_ij = 0.0;

        for (uint32_t n = 0; n < TILE_DIM; n++)
        {
            J_ij += ERIs[n][threadIdx.x];
        }

        mat_J[ij] += J_ij;
    }
}

__global__ void __launch_bounds__(TILE_SIZE_J)
computeCoulombFockDDSS(double*         mat_J,
                       const double*   s_prim_info,
                       const uint32_t  s_prim_count,
                       const double*   d_prim_info,
                       const uint32_t  d_prim_count,
                       const double*   ss_mat_D,
                       const double*   dd_mat_Q_local,
                       const double*   ss_mat_Q,
                       const uint32_t* dd_first_inds_local,
                       const uint32_t* dd_second_inds_local,
                       const double*   dd_pair_data_local,
                       const uint32_t  dd_prim_pair_count_local,
                       const uint32_t* ss_first_inds,
                       const uint32_t* ss_second_inds,
                       const double*   ss_pair_data,
                       const uint32_t  ss_prim_pair_count,
                       const double*   boys_func_table,
                       const double*   boys_func_ft,
                       const double    eri_threshold)
{
    // each thread row scans over [ij|??] and sum up to a primitive J matrix element
    // J. Chem. Theory Comput. 2009, 5, 4, 1004-1015

    __shared__ double   ERIs[TILE_DIM_LARGE + 1];
    __shared__ uint32_t d_cart_inds[6][2];
    __shared__ double   delta[3][3];

    __shared__ double a_i, a_j, r_i[3], r_j[3], S_ij_00, S1, inv_S1;
    __shared__ double PA_0, PA_1, PB_0, PB_1;
    __shared__ uint32_t i, j, a0, a1, b0, b1;

    const uint32_t ij = blockDim.x * blockIdx.x + threadIdx.x;

    if ((threadIdx.y == 0) && (threadIdx.x == 0))
    {

        d_cart_inds[0][0] = 0; d_cart_inds[0][1] = 0;
        d_cart_inds[1][0] = 0; d_cart_inds[1][1] = 1;
        d_cart_inds[2][0] = 0; d_cart_inds[2][1] = 2;
        d_cart_inds[3][0] = 1; d_cart_inds[3][1] = 1;
        d_cart_inds[4][0] = 1; d_cart_inds[4][1] = 2;
        d_cart_inds[5][0] = 2; d_cart_inds[5][1] = 2;

        delta[0][0] = 1.0; delta[0][1] = 0.0; delta[0][2] = 0.0;
        delta[1][0] = 0.0; delta[1][1] = 1.0; delta[1][2] = 0.0;
        delta[2][0] = 0.0; delta[2][1] = 0.0; delta[2][2] = 1.0;

        if (ij < dd_prim_pair_count_local)
        {
            i = dd_first_inds_local[ij];
            j = dd_second_inds_local[ij];

            a_i = d_prim_info[i / 6 + d_prim_count * 0];

            r_i[0] = d_prim_info[i / 6 + d_prim_count * 2];
            r_i[1] = d_prim_info[i / 6 + d_prim_count * 3];
            r_i[2] = d_prim_info[i / 6 + d_prim_count * 4];

            a_j = d_prim_info[j / 6 + d_prim_count * 0];

            r_j[0] = d_prim_info[j / 6 + d_prim_count * 2];
            r_j[1] = d_prim_info[j / 6 + d_prim_count * 3];
            r_j[2] = d_prim_info[j / 6 + d_prim_count * 4];

            S1 = a_i + a_j;
            inv_S1 = 1.0 / S1;

            S_ij_00 = dd_pair_data_local[ij];

            a0 = d_cart_inds[i % 6][0];
            a1 = d_cart_inds[i % 6][1];
            b0 = d_cart_inds[j % 6][0];
            b1 = d_cart_inds[j % 6][1];

            PA_0 = (a_j  * inv_S1) * (r_j[a0] - r_i[a0]);
            PA_1 = (a_j  * inv_S1) * (r_j[a1] - r_i[a1]);
            PB_0 = (-a_i * inv_S1) * (r_j[b0] - r_i[b0]);
            PB_1 = (-a_i * inv_S1) * (r_j[b1] - r_i[b1]);

        }

    }

    ERIs[threadIdx.y] = 0.0;

    __syncthreads();

    for (uint32_t m = 0; m < (ss_prim_pair_count + TILE_DIM_LARGE - 1) / TILE_DIM_LARGE; m++)
    {
        const uint32_t kl = m * TILE_DIM_LARGE + threadIdx.y;

        if ((ij >= dd_prim_pair_count_local) || (kl >= ss_prim_pair_count) || (fabs(dd_mat_Q_local[ij] * ss_mat_Q[kl] * ss_mat_D[kl]) <= eri_threshold))
        {
            break;
        }

        const auto k = ss_first_inds[kl];
        const auto l = ss_second_inds[kl];

        const auto a_k = s_prim_info[k + s_prim_count * 0];

        const double r_k[3] = {s_prim_info[k + s_prim_count * 2],
                               s_prim_info[k + s_prim_count * 3],
                               s_prim_info[k + s_prim_count * 4]};

        const auto a_l = s_prim_info[l + s_prim_count * 0];

        const double r_l[3] = {s_prim_info[l + s_prim_count * 2],
                               s_prim_info[l + s_prim_count * 3],
                               s_prim_info[l + s_prim_count * 4]};

        const auto S_kl_00 = ss_pair_data[kl];


        // J. Chem. Phys. 84, 3963-3974 (1986)

        const auto S2 = a_k + a_l;

        const auto inv_S2 = 1.0 / S2;
        const auto inv_S4 = 1.0 / (S1 + S2);

        const double PQ[3] = {(a_k * r_k[0] + a_l * r_l[0]) * inv_S2 - (a_i * r_i[0] + a_j * r_j[0]) * inv_S1,
                              (a_k * r_k[1] + a_l * r_l[1]) * inv_S2 - (a_i * r_i[1] + a_j * r_j[1]) * inv_S1,
                              (a_k * r_k[2] + a_l * r_l[2]) * inv_S2 - (a_i * r_i[2] + a_j * r_j[2]) * inv_S1};

        const auto r2_PQ = PQ[0] * PQ[0] + PQ[1] * PQ[1] + PQ[2] * PQ[2];

        const auto Lambda = sqrt(4.0 * S1 * S2 * MATH_CONST_INV_PI * inv_S4);

        double F4_t[5];

        gpu::computeBoysFunction(F4_t, S1 * S2 * inv_S4 * r2_PQ, 4, boys_func_table, boys_func_ft);


        const double eri_ijkl = Lambda * S_ij_00 * S_kl_00 * (

                + F4_t[0] * (

                    0.5 * inv_S1 * (
                        +PA_0*PB_0*delta[a1][b1]

                        +PA_1*(PA_0*delta[b0][b1] + PB_0*delta[a0][b1] + PB_1*delta[a0][b0]) + PB_1*(PA_0*delta[a1][b0] + PB_0*delta[a0][a1])
                    )

                    + (
                        +PA_0*PA_1*PB_0*PB_1
                    )

                    + 0.25 * inv_S1 * inv_S1 * (
                        +delta[a0][a1]*delta[b0][b1] + delta[a0][b0]*delta[a1][b1] + delta[a0][b1]*delta[a1][b0]
                    )

                )

                + F4_t[1] * (

                    (-0.5) * S2 * inv_S1 * inv_S1 * inv_S4 * (
                        +delta[a0][a1]*delta[b0][b1] + delta[a0][b0]*delta[a1][b1] + delta[a0][b1]*delta[a1][b0]
                    )

                    + 0.5 * S2 * inv_S1 * inv_S4 * (
                        +delta[b0][b1]*(PA_0*(-PA_1 + PQ[a1]) + PA_1*PQ[a0])

                        +PB_0*(-PA_0*delta[a1][b1] - PA_1*delta[a0][b1] - PB_1*delta[a0][a1] + PQ[a0]*delta[a1][b1] + PQ[a1]*delta[a0][b1] + PQ[b1]*delta[a0][a1]) + PQ[b0]*(PA_0*delta[a1][b1] + PA_1*delta[a0][b1] + PB_1*delta[a0][a1]) + delta[a0][b0]*(PA_1*(-PB_1 + PQ[b1]) + PB_1*PQ[a1]) + delta[a1][b0]*(PA_0*(-PB_1 + PQ[b1]) + PB_1*PQ[a0])
                    )

                    + S2 * inv_S4 * (
                        +PA_0*PA_1*(PB_0*PQ[b1] + PB_1*PQ[b0]) + PB_0*PB_1*(PA_0*PQ[a1] + PA_1*PQ[a0])
                    )

                )

                + F4_t[2] * (

                    0.5 * S2 * S2 * inv_S1 * inv_S4 * inv_S4 * (
                        +delta[b0][b1]*(-PA_0*PQ[a1] + PQ[a0]*(-PA_1 + PQ[a1]))

                        -PB_0*(PQ[a0]*delta[a1][b1] + PQ[a1]*delta[a0][b1]) - PB_1*(PQ[a0]*delta[a1][b0] + PQ[a1]*delta[a0][b0]) + PQ[b0]*(-PA_0*delta[a1][b1] - PA_1*delta[a0][b1] - PB_1*delta[a0][a1] + PQ[a0]*delta[a1][b1] + PQ[a1]*delta[a0][b1] + PQ[b1]*delta[a0][a1]) + PQ[b1]*(-PA_0*delta[a1][b0] - PA_1*delta[a0][b0] - PB_0*delta[a0][a1] + PQ[a0]*delta[a1][b0] + PQ[a1]*delta[a0][b0])
                    )

                    + S2 * S2 * inv_S4 * inv_S4 * (
                        +PA_0*PQ[b0]*(PA_1*PQ[b1] + PB_1*PQ[a1]) + PA_1*PQ[a0]*(PB_0*PQ[b1] + PB_1*PQ[b0]) + PB_0*PQ[a1]*(PA_0*PQ[b1] + PB_1*PQ[a0])
                    )

                    + 0.25 * S2 * S2 * inv_S1 * inv_S1 * inv_S4 * inv_S4 * (
                        +delta[a0][a1]*delta[b0][b1] + delta[a0][b0]*delta[a1][b1] + delta[a0][b1]*delta[a1][b0]
                    )

                )

                + F4_t[3] * (

                    (-0.5) * S2 * S2 * S2 * inv_S1 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[a0]*PQ[a1]*delta[b0][b1]

                        +PQ[b0]*(PQ[a0]*delta[a1][b1] + PQ[a1]*delta[a0][b1] + PQ[b1]*delta[a0][a1]) + PQ[b1]*(PQ[a0]*delta[a1][b0] + PQ[a1]*delta[a0][b0])
                    )

                    + S2 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[a0]*PQ[b1]*(PA_1*PQ[b0] + PB_0*PQ[a1]) + PQ[a1]*PQ[b0]*(PA_0*PQ[b1] + PB_1*PQ[a0])
                    )

                )

                + F4_t[4] * (

                    S2 * S2 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[a0]*PQ[a1]*PQ[b0]*PQ[b1]
                    )

                )

                );

        // NOTE: doubling for off-diagonal elements of D due to k<=>l symmetry
        //       (static_cast<double>(k != l) + 1.0) == (k == l ? 1.0 : 2.0)
        ERIs[threadIdx.y] += eri_ijkl * ss_mat_D[kl] * (static_cast<double>(k != l) + 1.0);
    }

    __syncthreads();

    if ((threadIdx.y == 0) && (ij < dd_prim_pair_count_local))
    {
        double J_ij = 0.0;

        for (uint32_t n = 0; n < TILE_DIM_LARGE; n++)
        {
            J_ij += ERIs[n];
        }

        mat_J[ij] += J_ij;
    }
}

__global__ void __launch_bounds__(TILE_SIZE_J)
computeCoulombFockDDSP(double*         mat_J,
                       const double*   s_prim_info,
                       const uint32_t  s_prim_count,
                       const double*   p_prim_info,
                       const uint32_t  p_prim_count,
                       const double*   d_prim_info,
                       const uint32_t  d_prim_count,
                       const double*   sp_mat_D,
                       const double*   dd_mat_Q_local,
                       const double*   sp_mat_Q,
                       const uint32_t* dd_first_inds_local,
                       const uint32_t* dd_second_inds_local,
                       const double*   dd_pair_data_local,
                       const uint32_t  dd_prim_pair_count_local,
                       const uint32_t* sp_first_inds,
                       const uint32_t* sp_second_inds,
                       const double*   sp_pair_data,
                       const uint32_t  sp_prim_pair_count,
                       const double*   boys_func_table,
                       const double*   boys_func_ft,
                       const double    eri_threshold)
{
    // each thread row scans over [ij|??] and sum up to a primitive J matrix element
    // J. Chem. Theory Comput. 2009, 5, 4, 1004-1015

    __shared__ double   ERIs[TILE_DIM_LARGE + 1];
    __shared__ uint32_t d_cart_inds[6][2];
    __shared__ double   delta[3][3];

    __shared__ double a_i, a_j, r_i[3], r_j[3], S_ij_00, S1, inv_S1;
    __shared__ double PA_0, PA_1, PB_0, PB_1;
    __shared__ uint32_t i, j, a0, a1, b0, b1;

    const uint32_t ij = blockDim.x * blockIdx.x + threadIdx.x;

    if ((threadIdx.y == 0) && (threadIdx.x == 0))
    {

        d_cart_inds[0][0] = 0; d_cart_inds[0][1] = 0;
        d_cart_inds[1][0] = 0; d_cart_inds[1][1] = 1;
        d_cart_inds[2][0] = 0; d_cart_inds[2][1] = 2;
        d_cart_inds[3][0] = 1; d_cart_inds[3][1] = 1;
        d_cart_inds[4][0] = 1; d_cart_inds[4][1] = 2;
        d_cart_inds[5][0] = 2; d_cart_inds[5][1] = 2;

        delta[0][0] = 1.0; delta[0][1] = 0.0; delta[0][2] = 0.0;
        delta[1][0] = 0.0; delta[1][1] = 1.0; delta[1][2] = 0.0;
        delta[2][0] = 0.0; delta[2][1] = 0.0; delta[2][2] = 1.0;

        if (ij < dd_prim_pair_count_local)
        {
            i = dd_first_inds_local[ij];
            j = dd_second_inds_local[ij];

            a_i = d_prim_info[i / 6 + d_prim_count * 0];

            r_i[0] = d_prim_info[i / 6 + d_prim_count * 2];
            r_i[1] = d_prim_info[i / 6 + d_prim_count * 3];
            r_i[2] = d_prim_info[i / 6 + d_prim_count * 4];

            a_j = d_prim_info[j / 6 + d_prim_count * 0];

            r_j[0] = d_prim_info[j / 6 + d_prim_count * 2];
            r_j[1] = d_prim_info[j / 6 + d_prim_count * 3];
            r_j[2] = d_prim_info[j / 6 + d_prim_count * 4];

            S1 = a_i + a_j;
            inv_S1 = 1.0 / S1;

            S_ij_00 = dd_pair_data_local[ij];

            a0 = d_cart_inds[i % 6][0];
            a1 = d_cart_inds[i % 6][1];
            b0 = d_cart_inds[j % 6][0];
            b1 = d_cart_inds[j % 6][1];

            PA_0 = (a_j  * inv_S1) * (r_j[a0] - r_i[a0]);
            PA_1 = (a_j  * inv_S1) * (r_j[a1] - r_i[a1]);
            PB_0 = (-a_i * inv_S1) * (r_j[b0] - r_i[b0]);
            PB_1 = (-a_i * inv_S1) * (r_j[b1] - r_i[b1]);

        }

    }

    ERIs[threadIdx.y] = 0.0;

    __syncthreads();

    for (uint32_t m = 0; m < (sp_prim_pair_count + TILE_DIM_LARGE - 1) / TILE_DIM_LARGE; m++)
    {
        const uint32_t kl = m * TILE_DIM_LARGE + threadIdx.y;

        if ((ij >= dd_prim_pair_count_local) || (kl >= sp_prim_pair_count) || (fabs(dd_mat_Q_local[ij] * sp_mat_Q[kl] * sp_mat_D[kl]) <= eri_threshold))
        {
            break;
        }

        const auto k = sp_first_inds[kl];
        const auto l = sp_second_inds[kl];

        const auto a_k = s_prim_info[k + s_prim_count * 0];

        const double r_k[3] = {s_prim_info[k + s_prim_count * 2],
                               s_prim_info[k + s_prim_count * 3],
                               s_prim_info[k + s_prim_count * 4]};

        const auto a_l = p_prim_info[l / 3 + p_prim_count * 0];

        const double r_l[3] = {p_prim_info[l / 3 + p_prim_count * 2],
                               p_prim_info[l / 3 + p_prim_count * 3],
                               p_prim_info[l / 3 + p_prim_count * 4]};

        const auto S_kl_00 = sp_pair_data[kl];

        const auto d0 = l % 3;

        // J. Chem. Phys. 84, 3963-3974 (1986)

        const auto S2 = a_k + a_l;

        const auto inv_S2 = 1.0 / S2;
        const auto inv_S4 = 1.0 / (S1 + S2);

        const double PQ[3] = {(a_k * r_k[0] + a_l * r_l[0]) * inv_S2 - (a_i * r_i[0] + a_j * r_j[0]) * inv_S1,
                              (a_k * r_k[1] + a_l * r_l[1]) * inv_S2 - (a_i * r_i[1] + a_j * r_j[1]) * inv_S1,
                              (a_k * r_k[2] + a_l * r_l[2]) * inv_S2 - (a_i * r_i[2] + a_j * r_j[2]) * inv_S1};

        const auto r2_PQ = PQ[0] * PQ[0] + PQ[1] * PQ[1] + PQ[2] * PQ[2];

        const auto Lambda = sqrt(4.0 * S1 * S2 * MATH_CONST_INV_PI * inv_S4);

        double F5_t[6];

        gpu::computeBoysFunction(F5_t, S1 * S2 * inv_S4 * r2_PQ, 5, boys_func_table, boys_func_ft);

        const auto QD_0 = (-a_k * inv_S2) * (r_l[d0] - r_k[d0]);

        const double eri_ijkl = Lambda * S_ij_00 * S_kl_00 * (

                + F5_t[0] * (

                    0.25 * inv_S1 * inv_S1 * (
                        +QD_0*(delta[a0][a1]*delta[b0][b1] + delta[a0][b0]*delta[a1][b1] + delta[a0][b1]*delta[a1][b0])
                    )

                    + 0.5 * inv_S1 * (
                        +PA_0*PA_1*QD_0*delta[b0][b1]

                        +QD_0*(PB_0*(PA_0*delta[a1][b1] + PA_1*delta[a0][b1] + PB_1*delta[a0][a1]) + PB_1*(PA_0*delta[a1][b0] + PA_1*delta[a0][b0]))
                    )

                    + (
                        +PA_0*PA_1*PB_0*PB_1*QD_0
                    )

                )

                + F5_t[1] * (

                    (-0.5) * S2 * inv_S1 * inv_S1 * inv_S4 * (
                        +QD_0*(delta[a0][a1]*delta[b0][b1] + delta[a0][b0]*delta[a1][b1] + delta[a0][b1]*delta[a1][b0])
                    )

                    + 0.25 * inv_S1 * inv_S4 * (
                        +PB_0*(delta[a0][a1]*delta[b1][d0] + delta[a0][b1]*delta[a1][d0] + delta[a0][d0]*delta[a1][b1])

                        +PA_0*(delta[a1][b0]*delta[b1][d0] + delta[a1][b1]*delta[b0][d0] + delta[a1][d0]*delta[b0][b1]) + PA_1*(delta[a0][b0]*delta[b1][d0] + delta[a0][b1]*delta[b0][d0] + delta[a0][d0]*delta[b0][b1]) + PB_1*(delta[a0][a1]*delta[b0][d0] + delta[a0][b0]*delta[a1][d0] + delta[a0][d0]*delta[a1][b0])

                        +PQ[d0]*(-delta[a0][a1]*delta[b0][b1] - delta[a0][b0]*delta[a1][b1] - delta[a0][b1]*delta[a1][b0])
                    )

                    + 0.5 * S2 * inv_S1 * inv_S4 * (
                        +QD_0*delta[b0][b1]*(PA_0*(-PA_1 + PQ[a1]) + PA_1*PQ[a0])

                        +QD_0*(PB_0*(-PA_0*delta[a1][b1] - PA_1*delta[a0][b1] - PB_1*delta[a0][a1] + PQ[a0]*delta[a1][b1] + PQ[a1]*delta[a0][b1] + PQ[b1]*delta[a0][a1]) + PQ[b0]*(PA_0*delta[a1][b1] + PA_1*delta[a0][b1] + PB_1*delta[a0][a1]) + delta[a0][b0]*(PA_1*(-PB_1 + PQ[b1]) + PB_1*PQ[a1]) + delta[a1][b0]*(PA_0*(-PB_1 + PQ[b1]) + PB_1*PQ[a0]))
                    )

                    + 0.5 * inv_S4 * (
                        +PA_0*PA_1*PB_0*delta[b1][d0]

                        +PB_1*(PA_0*(PA_1*delta[b0][d0] + PB_0*delta[a1][d0]) + PA_1*PB_0*delta[a0][d0])

                        +PQ[d0]*(-PA_0*(PA_1*delta[b0][b1] + PB_0*delta[a1][b1] + PB_1*delta[a1][b0]) - PA_1*(PB_0*delta[a0][b1] + PB_1*delta[a0][b0]) - PB_0*PB_1*delta[a0][a1])
                    )

                    + S1 * inv_S4 * (
                        -PA_0*PA_1*PB_0*PB_1*PQ[d0]
                    )

                    + S2 * inv_S4 * (
                        +QD_0*(PA_0*PA_1*(PB_0*PQ[b1] + PB_1*PQ[b0]) + PB_0*PB_1*(PA_0*PQ[a1] + PA_1*PQ[a0]))
                    )

                )

                + F5_t[2] * (

                    0.25 * S2 * S2 * inv_S1 * inv_S1 * inv_S4 * inv_S4 * (
                        +QD_0*(delta[a0][a1]*delta[b0][b1] + delta[a0][b0]*delta[a1][b1] + delta[a0][b1]*delta[a1][b0])
                    )

                    + 0.25 * S2 * inv_S1 * inv_S4 * inv_S4 * (
                        +(-PA_0 + PQ[a0])*(delta[a1][b0]*delta[b1][d0] + delta[a1][b1]*delta[b0][d0] + delta[a1][d0]*delta[b0][b1])

                        +(-PA_1 + PQ[a1])*(delta[a0][b0]*delta[b1][d0] + delta[a0][b1]*delta[b0][d0] + delta[a0][d0]*delta[b0][b1]) + (-PB_0 + PQ[b0])*(delta[a0][a1]*delta[b1][d0] + delta[a0][b1]*delta[a1][d0] + delta[a0][d0]*delta[a1][b1]) + (-PB_1 + PQ[b1])*(delta[a0][a1]*delta[b0][d0] + delta[a0][b0]*delta[a1][d0] + delta[a0][d0]*delta[a1][b0])

                        +2.0*PQ[d0]*(delta[a0][a1]*delta[b0][b1] + delta[a0][b0]*delta[a1][b1] + delta[a0][b1]*delta[a1][b0])
                    )

                    + 0.5 * S2 * S2 * inv_S1 * inv_S4 * inv_S4 * (
                        +QD_0*delta[b0][b1]*(-PA_0*PQ[a1] + PQ[a0]*(-PA_1 + PQ[a1]))

                        +QD_0*(PQ[a0]*delta[a1][b0]*(-PB_1 + PQ[b1]) + PQ[a0]*delta[a1][b1]*(-PB_0 + PQ[b0]) + PQ[a1]*delta[a0][b0]*(-PB_1 + PQ[b1]) + PQ[a1]*delta[a0][b1]*(-PB_0 + PQ[b0]) + PQ[b0]*PQ[b1]*delta[a0][a1] - PQ[b0]*(PA_0*delta[a1][b1] + PA_1*delta[a0][b1] + PB_1*delta[a0][a1]) - PQ[b1]*(PA_0*delta[a1][b0] + PA_1*delta[a0][b0] + PB_0*delta[a0][a1]))
                    )

                    + 0.5 * S2 * inv_S4 * inv_S4 * (
                        +delta[b1][d0]*(PA_0*(PA_1*PQ[b0] + PB_0*PQ[a1]) + PA_1*PB_0*PQ[a0])

                        +PA_0*PQ[b1]*(PA_1*delta[b0][d0] + PB_0*delta[a1][d0]) + PA_1*delta[a0][d0]*(PB_0*PQ[b1] + PB_1*PQ[b0]) + PB_1*(PA_0*(PQ[a1]*delta[b0][d0] + PQ[b0]*delta[a1][d0]) + PB_0*PQ[a1]*delta[a0][d0] + PQ[a0]*(PA_1*delta[b0][d0] + PB_0*delta[a1][d0]))

                        +PQ[d0]*(PA_0*PA_1*delta[b0][b1] - PA_0*(PQ[a1]*delta[b0][b1] + PQ[b0]*delta[a1][b1] + PQ[b1]*delta[a1][b0]) - PA_1*(PQ[a0]*delta[b0][b1] + PQ[b0]*delta[a0][b1] + PQ[b1]*delta[a0][b0]) + PB_0*(PA_0*delta[a1][b1] + PA_1*delta[a0][b1] + PB_1*delta[a0][a1] - PQ[a0]*delta[a1][b1] - PQ[a1]*delta[a0][b1] - PQ[b1]*delta[a0][a1]) + PB_1*(PA_0*delta[a1][b0] + PA_1*delta[a0][b0] - PQ[a0]*delta[a1][b0] - PQ[a1]*delta[a0][b0] - PQ[b0]*delta[a0][a1]))
                    )

                    + S1 * S2 * inv_S4 * inv_S4 * (
                        -PQ[d0]*(PA_0*PA_1*(PB_0*PQ[b1] + PB_1*PQ[b0]) + PB_0*PB_1*(PA_0*PQ[a1] + PA_1*PQ[a0]))
                    )

                    + S2 * S2 * inv_S4 * inv_S4 * (
                        +QD_0*(PA_0*PQ[b0]*(PA_1*PQ[b1] + PB_1*PQ[a1]) + PA_1*PQ[a0]*(PB_0*PQ[b1] + PB_1*PQ[b0]) + PB_0*PQ[a1]*(PA_0*PQ[b1] + PB_1*PQ[a0]))
                    )

                )

                + F5_t[3] * (

                    (-0.25) * S2 * S2 * inv_S1 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[a0]*(delta[a1][b0]*delta[b1][d0] + delta[a1][b1]*delta[b0][d0] + delta[a1][d0]*delta[b0][b1])

                        +PQ[a1]*(delta[a0][b0]*delta[b1][d0] + delta[a0][b1]*delta[b0][d0] + delta[a0][d0]*delta[b0][b1]) + PQ[b0]*(delta[a0][a1]*delta[b1][d0] + delta[a0][b1]*delta[a1][d0] + delta[a0][d0]*delta[a1][b1]) + PQ[b1]*(delta[a0][a1]*delta[b0][d0] + delta[a0][b0]*delta[a1][d0] + delta[a0][d0]*delta[a1][b0]) + PQ[d0]*(delta[a0][a1]*delta[b0][b1] + delta[a0][b0]*delta[a1][b1] + delta[a0][b1]*delta[a1][b0])
                    )

                    + (-0.5) * S2 * S2 * S2 * inv_S1 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[a0]*PQ[a1]*QD_0*delta[b0][b1]

                        +QD_0*(PQ[b0]*(PQ[a0]*delta[a1][b1] + PQ[a1]*delta[a0][b1] + PQ[b1]*delta[a0][a1]) + PQ[b1]*(PQ[a0]*delta[a1][b0] + PQ[a1]*delta[a0][b0]))
                    )

                    + 0.5 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * (
                        +delta[b1][d0]*(PA_1*PQ[a0]*PQ[b0] + PQ[a1]*(PA_0*PQ[b0] + PB_0*PQ[a0]))

                        +PB_1*(PQ[a0]*(PQ[a1]*delta[b0][d0] + PQ[b0]*delta[a1][d0]) + PQ[a1]*PQ[b0]*delta[a0][d0]) + PQ[b1]*(PA_0*(PQ[a1]*delta[b0][d0] + PQ[b0]*delta[a1][d0]) + PA_1*(PQ[a0]*delta[b0][d0] + PQ[b0]*delta[a0][d0]) + PB_0*(PQ[a0]*delta[a1][d0] + PQ[a1]*delta[a0][d0]))

                        +PQ[d0]*(PA_0*(PQ[a1]*delta[b0][b1] + PQ[b0]*delta[a1][b1] + PQ[b1]*delta[a1][b0]) + PQ[a0]*(PA_1*delta[b0][b1] + PB_0*delta[a1][b1] + PB_1*delta[a1][b0] - PQ[a1]*delta[b0][b1] - PQ[b0]*delta[a1][b1] - PQ[b1]*delta[a1][b0]) + PQ[a1]*(PB_0*delta[a0][b1] + PB_1*delta[a0][b0]) + PQ[b0]*(PB_1*delta[a0][a1] + delta[a0][b1]*(PA_1 - PQ[a1])) + PQ[b1]*(delta[a0][a1]*(PB_0 - PQ[b0]) + delta[a0][b0]*(PA_1 - PQ[a1])))
                    )

                    + (-1.0) * S1 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * (
                        +PA_0*PA_1*PQ[b0]*PQ[b1]*PQ[d0]

                        +PQ[d0]*(PA_1*PQ[a0]*(PB_0*PQ[b1] + PB_1*PQ[b0]) + PQ[a1]*(PA_0*(PB_0*PQ[b1] + PB_1*PQ[b0]) + PB_0*PB_1*PQ[a0]))
                    )

                    + S2 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * (
                        +QD_0*(PQ[a0]*PQ[b1]*(PA_1*PQ[b0] + PB_0*PQ[a1]) + PQ[a1]*PQ[b0]*(PA_0*PQ[b1] + PB_1*PQ[a0]))
                    )

                )

                + F5_t[4] * (

                    (-1.0) * S1 * S2 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (
                        +PA_0*PQ[a1]*PQ[b0]*PQ[b1]*PQ[d0]

                        +PQ[a0]*PQ[d0]*(PB_0*PQ[a1]*PQ[b1] + PQ[b0]*(PA_1*PQ[b1] + PB_1*PQ[a1]))
                    )

                    + S2 * S2 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[a0]*PQ[a1]*PQ[b0]*PQ[b1]*QD_0
                    )

                    + 0.5 * S2 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[a0]*PQ[a1]*PQ[b0]*delta[b1][d0]

                        +PQ[b1]*(PQ[a0]*(PQ[a1]*delta[b0][d0] + PQ[b0]*delta[a1][d0] + PQ[d0]*delta[a1][b0]) + PQ[a1]*(PQ[b0]*delta[a0][d0] + PQ[d0]*delta[a0][b0])) + PQ[d0]*(PQ[a0]*(PQ[a1]*delta[b0][b1] + PQ[b0]*delta[a1][b1]) + PQ[b0]*(PQ[a1]*delta[a0][b1] + PQ[b1]*delta[a0][a1]))
                    )

                )

                + F5_t[5] * (

                    (-1.0) * S1 * S2 * S2 * S2 * S2 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * inv_S4 * (
                        +PQ[a0]*PQ[a1]*PQ[b0]*PQ[b1]*PQ[d0]
                    )

                )

                );

        // NOTE: doubling for off-diagonal elements of D due to k<=>l symmetry
        ERIs[threadIdx.y] += eri_ijkl * sp_mat_D[kl] * 2.0;
    }

    __syncthreads();

    if ((threadIdx.y == 0) && (ij < dd_prim_pair_count_local))
    {
        double J_ij = 0.0;

        for (uint32_t n = 0; n < TILE_DIM_LARGE; n++)
        {
            J_ij += ERIs[n];
        }

        mat_J[ij] += J_ij;
    }
}

__global__ void __launch_bounds__(TILE_SIZE_J)
computeCoulombFockDDSD(double*         mat_J,
                       const double*   s_prim_info,
                       const uint32_t  s_prim_count,
                       const double*   d_prim_info,
                       const uint32_t  d_prim_count,
                       const double*   sd_mat_D,
                       const double*   dd_mat_Q_local,
                       const double*   sd_mat_Q,
                       const uint32_t* dd_first_inds_local,
                       const uint32_t* dd_second_inds_local,
                       const double*   dd_pair_data_local,
                       const uint32_t  dd_prim_pair_count_local,
                       const uint32_t* sd_first_inds,
                       const uint32_t* sd_second_inds,
                       const double*   sd_pair_data,
                       const uint32_t  sd_prim_pair_count,
                       const double*   boys_func_table,
                       const double*   boys_func_ft,
                       const double    eri_threshold)
{
    // each thread row scans over [ij|??] and sum up to a primitive J matrix element
    // J. Chem. Theory Comput. 2009, 5, 4, 1004-1015

    __shared__ double   ERIs[TILE_DIM_LARGE + 1];
    __shared__ uint32_t d_cart_inds[6][2];
    __shared__ double   delta[3][3];

    __shared__ double a_i, a_j, r_i[3], r_j[3], S_ij_00, S1, inv_S1;
    __shared__ double PA_0, PA_1, PB_0, PB_1;
    __shared__ uint32_t i, j, a0, a1, b0, b1;

    const uint32_t ij = blockDim.x * blockIdx.x + threadIdx.x;

    if ((threadIdx.y == 0) && (threadIdx.x == 0))
    {

        d_cart_inds[0][0] = 0; d_cart_inds[0][1] = 0;
        d_cart_inds[1][0] = 0; d_cart_inds[1][1] = 1;
        d_cart_inds[2][0] = 0; d_cart_inds[2][1] = 2;
        d_cart_inds[3][0] = 1; d_cart_inds[3][1] = 1;
        d_cart_inds[4][0] = 1; d_cart_inds[4][1] = 2;
        d_cart_inds[5][0] = 2; d_cart_inds[5][1] = 2;

        delta[0][0] = 1.0; delta[0][1] = 0.0; delta[0][2] = 0.0;
        delta[1][0] = 0.0; delta[1][1] = 1.0; delta[1][2] = 0.0;
        delta[2][0] = 0.0; delta[2][1] = 0.0; delta[2][2] = 1.0;

        if (ij < dd_prim_pair_count_local)
        {
            i = dd_first_inds_local[ij];
            j = dd_second_inds_local[ij];

            a_i = d_prim_info[i / 6 + d_prim_count * 0];

            r_i[0] = d_prim_info[i / 6 + d_prim_count * 2];
            r_i[1] = d_prim_info[i / 6 + d_prim_count * 3];
            r_i[2] = d_prim_info[i / 6 + d_prim_count * 4];

            a_j = d_prim_info[j / 6 + d_prim_count * 0];

            r_j[0] = d_prim_info[j / 6 + d_prim_count * 2];
            r_j[1] = d_prim_info[j / 6 + d_prim_count * 3];
            r_j[2] = d_prim_info[j / 6 + d_prim_count * 4];

            S1 = a_i + a_j;
            inv_S1 = 1.0 / S1;

            S_ij_00 = dd_pair_data_local[ij];

            a0 = d_cart_inds[i % 6][0];
            a1 = d_cart_inds[i % 6][1];
            b0 = d_cart_inds[j % 6][0];
            b1 = d_cart_inds[j % 6][1];

            PA_0 = (a_j  * inv_S1) * (r_j[a0] - r_i[a0]);
            PA_1 = (a_j  * inv_S1) * (r_j[a1] - r_i[a1]);
            PB_0 = (-a_i * inv_S1) * (r_j[b0] - r_i[b0]);
            PB_1 = (-a_i * inv_S1) * (r_j[b1] - r_i[b1]);

        }

    }

    ERIs[threadIdx.y] = 0.0;

    __syncthreads();

    for (uint32_t m = 0; m < (sd_prim_pair_count + TILE_DIM_LARGE - 1) / TILE_DIM_LARGE; m++)
    {
        const uint32_t kl = m * TILE_DIM_LARGE + threadIdx.y;

        if ((ij >= dd_prim_pair_count_local) || (kl >= sd_prim_pair_count) || (fabs(dd_mat_Q_local[ij] * sd_mat_Q[kl] * sd_mat_D[kl]) <= eri_threshold))
        {
            break;
        }

        const auto k = sd_first_inds[kl];
        const auto l = sd_second_inds[kl];

        const auto a_k = s_prim_info[k + s_prim_count * 0];

        const double r_k[3] = {s_prim_info[k + s_prim_count * 2],
                               s_prim_info[k + s_prim_count * 3],
                               s_prim_info[k + s_prim_count * 4]};

        const auto a_l = d_prim_info[l / 6 + d_prim_count * 0];

        const double r_l[3] = {d_prim_info[l / 6 + d_prim_count * 2],
                               d_prim_info[l / 6 + d_prim_count * 3],
                               d_prim_info[l / 6 + d_prim_count * 4]};

        const auto S_kl_00 = sd_pair_data[kl];

        const auto d0 = d_cart_inds[l % 6][0];
        const auto d1 = d_cart_inds[l % 6][1];

        // J. Chem. Phys. 84, 3963-3974 (1986)

        const auto S2 = a_k + a_l;

        const auto inv_S2 = 1.0 / S2;
        const auto inv_S4 = 1.0 / (S1 + S2);

        const double PQ[3] = {(a_k * r_k[0] + a_l * r_l[0]) * inv_S2 - (a_i * r_i[0] + a_j * r_j[0]) * inv_S1,
                              (a_k * r_k[1] + a_l * r_l[1]) * inv_S2 - (a_i * r_i[1] + a_j * r_j[1]) * inv_S1,
                              (a_k * r_k[2] + a_l * r_l[2]) * inv_S2 - (a_i * r_i[2] + a_j * r_j[2]) * inv_S1};

        const auto r2_PQ = PQ[0] * PQ[0] + PQ[1] * PQ[1] + PQ[2] * PQ[2];

        const auto Lambda = sqrt(4.0 * S1 * S2 * MATH_CONST_INV_PI * inv_S4);

        double F6_t[7];

        gpu::computeBoysFunction(F6_t, S1 * S2 * inv_S4 * r2_PQ, 6, boys_func_table, boys_func_ft);

        const auto QD_0 = (-a_k * inv_S2) * (r_l[d0] - r_k[d0]);
        const auto QD_1 = (-a_k * inv_S2) * (r_l[d1] - r_k[d1]);

        const double eri_ijkl = Lambda * S_ij_00 * S_kl_00 * (

                + F6_t[0] * (

                    0.25 * inv_S1 * inv_S1 * (
                        +QD_0*QD_1*(delta[a0][a1]*delta[b0][b1] + delta[a0][b0]*delta[a1][b1] + delta[a0][b1]*delta[a1][b0])
                    )

                    + 0.25 * inv_S1 * inv_S2 * (
                        +PA_0*PB_0*delta[a1][b1]*delta[d0][d1]

                        +delta[d0][d1]*(PA_1*(PA_0*delta[b0][b1] + PB_0*delta[a0][b1] + PB_1*delta[a0][b0]) + PB_1*(PA_0*delta[a1][b0] + PB_0*delta[a0][a1]))
                    )

                    + 0.5 * inv_S1 * (
                        +PA_0*PA_1*QD_0*QD_1*delta[b0][b1]

                        +QD_0*QD_1*(PB_0*(PA_0*delta[a1][b1] + PA_1*delta[a0][b1] + PB_1*delta[a0][a1]) + PB_1*(PA_0*delta[a1][b0] + PA_1*delta[a0][b0]))
                    )

                    + 0.5 * inv_S2 * (
                        +PA_0*PA_1*PB_0*PB_1*delta[d0][d1]
                    )

                    + (
                        +PA_0*PA_1*PB_0*PB_1*QD_0*QD_1
                    )

                    + 0.125 * inv_S1 * inv_S1 * inv_S2 * (
                        +delta[d0][d1]*(delta[a0][a1]*delta[b0][b1] + delta[a0][b0]*delta[a1][b1] + delta[a0][b1]*delta[a1][b0])
                    )

                )

                + F6_t[1] * (

                    (-0.25) * inv_S1 * inv_S1 * inv_S4 * (
                        +delta[d0][d1]*(delta[a0][a1]*delta[b0][b1] + delta[a0][b0]*delta[a1][b1] + delta[a0][b1]*delta[a1][b0])
                    )

                    + (-0.125) * inv_S1 * inv_S2 * inv_S4 * (
                        +delta[d0][d1]*(delta[a0][a1]*delta[b0][b1] + delta[a0][b0]*delta[a1][b1] + delta[a0][b1]*delta[a1][b0])
                    )

                    + (-0.5) * S2 * inv_S1 * inv_S1 * inv_S4 * (
                        +QD_0*QD_1*(delta[a0][a1]*delta[b0][b1] + delta[a0][b0]*delta[a1][b1] + delta[a0][b1]*delta[a1][b0])
                    )

                    + 0.25 * inv_S1 * inv_S4 * (
                        +delta[b0][b1]*delta[d0][d1]*(PA_0*(-PA_1 + PQ[a1]) + PA_1*PQ[a0])

                        +delta[d0][d1]*(PB_0*(-PA_0*delta[a1][b1] - PA_1*delta[a0][b1] - PB_1*delta[a0][a1] + PQ[a0]*delta[a1][b1] + PQ[a1]*delta[a0][b1] + PQ[b1]*delta[a0][a1]) + PQ[b0]*(PA_0*delta[a1][b1] + PA_1*delta[a0][b1] + PB_1*delta[a0][a1]) + delta[a0][b0]*(PA_1*(-PB_1 + PQ[b1]) + PB_1*PQ[a1]) + delta[a1][b0]*(PA_0*(-PB_1 + PQ[b1]) + PB_1*PQ[a0]))

                        +QD_0*(PA_0*(delta[a1][b0]*delta[b1][d1] + delta[a1][b1]*delta[b0][d1] + delta[a1][d1]*delta[b0][b1]) + PA_1*(delta[a0][b0]*delta[b1][d1] + delta[a0][b1]*delta[b0][d1] + delta[a0][d1]*delta[b0][b1]) + PB_0*(delta[a0][a1]*delta[b1][d1] + delta[a0][b1]*delta[a1][d1] + delta[a0][d1]*delta[a1][b1]) + PB_1*(delta[a0][a1]*delta[b0][d1] + delta[a0][b0]*delta[a1][d1] + delta[a0][d1]*delta[a1][b0])) + QD_1*(PA_0*(delta[a1][b0]*delta[b1][d0] + delta[a1][b1]*delta[b0][d0] + delta[a1][d0]*delta[b0][b1]) + PA_1*(delta[a0][b0]*delta[b1][d0] + delta[a0][b1]*delta[b0][d0] + delta[a0][d0]*delta[b0][b1]) + PB_0*(delta[a0][a1]*delta[b1][d0] + delta[a0][b1]*delta[a1][d0] + delta[a0][d0]*delta[a1][b1]) + PB_1*(delta[a0][a1]*delta[b0][d0] + delta[a0][b0]*delta[a1][d0] + delta[a0][d0]*delta[a1][b0]))

                        -(PQ[d0]*QD_1 + PQ[d1]*QD_0)*(delta[a0][a1]*delta[b0][b1] + delta[a0][b0]*delta[a1][b1] + delta[a0][b1]*delta[a1][b0])
                    )

                    + (-0.25) * inv_S2 * inv_S4 * (
                        +PA_0*PA_1*delta[b0][b1]*delta[d0][d1]

                        +delta[d0][d1]*(PB_0*(PA_0*delta[a1][b1] + PA_1*delta[a0][b1] + PB_1*delta[a0][a1]) + PB_1*(PA_0*delta[a1][b0] + PA_1*delta[a0][b0]))
                    )

                    + (-0.5) * S1 * inv_S2 * inv_S4 * (
                        +PA_0*PA_1*PB_0*PB_1*delta[d0][d1]
                    )

                    + 0.5 * S2 * inv_S1 * inv_S4 * (
                        +QD_0*QD_1*delta[b0][b1]*(PA_0*(-PA_1 + PQ[a1]) + PA_1*PQ[a0])

                        +QD_0*QD_1*(PB_0*(-PA_0*delta[a1][b1] - PA_1*delta[a0][b1] - PB_1*delta[a0][a1] + PQ[a0]*delta[a1][b1] + PQ[a1]*delta[a0][b1] + PQ[b1]*delta[a0][a1]) + PQ[b0]*(PA_0*delta[a1][b1] + PA_1*delta[a0][b1] + PB_1*delta[a0][a1]) + delta[a0][b0]*(PA_1*(-PB_1 + PQ[b1]) + PB_1*PQ[a1]) + delta[a1][b0]*(PA_0*(-PB_1 + PQ[b1]) + PB_1*PQ[a0]))
                    )

                    + 0.5 * inv_S4 * (
                        +delta[d0][d1]*(PA_0*PA_1*(PB_0*PQ[b1] + PB_1*PQ[b0]) + PB_0*PB_1*(PA_0*PQ[a1] + PA_1*PQ[a0]))

